reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region = "us-east-1" 
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

# Create a VPC for internal resources
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/24"
}


# RDS instances
resource "aws_db_instance" "internal" {
  # Internal DB configuration
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  identifier =  "internal"
  username             = "user"
  password             = "password"
  db_subnet_group_name = aws_db_subnet_group.main.name
  skip_final_snapshot  = true
}

resource "aws_db_instance" "public" {
  # Public DB configuration
  publicly_accessible  = true
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  identifier = "public"
  username             = "user"
  password             = "password"
  skip_final_snapshot  = true
}

resource "aws_db_subnet_group" "main" {
  name       = "mydb-subnet-group"
  subnet_ids = [aws_subnet.maina.id, aws_subnet.mainb.id]
}

data "aws_availability_zones" "available" {}

# Subnet for RDS
resource "aws_subnet" "maina" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.0.0/25"
  availability_zone = data.aws_availability_zones.available.names[0]
}

resource "aws_subnet" "mainb" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.0.128/25"
  availability_zone = data.aws_availability_zones.available.names[1]
}

# Route 53 Public Hosted Zone for external users
resource "aws_route53_zone" "public" {
  name = "example53.com"
}

# Route 53 Private Hosted Zone for internal users
resource "aws_route53_zone" "private" {
  name = "example53.com"
  vpc {
    vpc_id = aws_vpc.main.id
  }
}

# Route 53 Record for Public DB (External Endpoint)
resource "aws_route53_record" "public_db" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "public-db.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.public.address]
}

# Route 53 Record for Internal DB (Internal Endpoint)
resource "aws_route53_record" "internal_db" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "internal-db.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.internal.address]
}

response:
Okay, let's break down this Terraform configuration step-by-step.

1.  **Provider Configuration:** We'll need the AWS provider configured.  I'll assume the region is set appropriately in the provider config.
2.  **Private Hosted Zone:**  Create a private hosted zone in Route 53 for internal traffic. This will be associated with a VPC. For now, I'll assume the VPC ID is known.
3.  **Public Hosted Zone:** Create a public hosted zone in Route 53 for external traffic.
4.  **Internal Database Record:** Create a record in the private hosted zone pointing to the internal RDS instance. Assume an internal RDS endpoint.
5.  **Public Database Record:** Create a record in the public hosted zone pointing to the public RDS instance. Assume a public RDS endpoint.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Private Hosted Zone for Internal Users
resource "aws_route53_zone" "private" {
  name = "private.example.com" # Ensure this is a valid private domain
  vpc_id     = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID
  private_zone = true
}

# Public Hosted Zone for External Users
resource "aws_route53_zone" "public" {
  name = "public.example.com" # Ensure this is a valid public domain
}

# Record for Internal Database in Private Zone
resource "aws_route53_record" "internal_db" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "internal.private.example.com" #Database name
  type    = "A"
  ttl     = "300"
  records = ["10.0.1.10"] # Replace with your internal RDS endpoint IP
}

# Record for Public Database in Public Zone
resource "aws_route53_record" "public_db" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "public.public.example.com" #Database name
  type    = "A"
  ttl     = "300"
  records = ["54.239.23.145"] # Replace with your public RDS endpoint IP
}
```

