  }
}

provider "aws" {
  region = "us-west-1"
  alias  = "west"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  region = "eu-central-1"
  alias  = "europe"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  provider = aws.default
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
