  region = "us-east-1" # Replace with your desired region
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "webapp-vpc"
  }
}

# Subnets
resource "aws_subnet" "subnet1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  tags = {
    Name = "webapp-subnet-1"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired AZ
  tags = {
    Name = "webapp-subnet-2"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "webapp-igw"
  }
}

# Route Tables
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "webapp-public-rt"
  }
}

resource "aws_route" "public_route" {
  route_table_id         = aws_route_table.public_rt.id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id             = aws_internet_gateway.gw.id
}

resource "aws_route_table_association" "subnet1_assoc" {
  subnet_id      = aws_subnet.subnet1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "subnet2_assoc" {
  subnet_id      = aws_subnet.subnet2.id
  route_table_id = aws_route_table.public_rt.id
}

# Security Groups
resource "aws_security_group" "webapp_sg" {
  name        = "webapp-sg"
  description = "Allow inbound traffic for web application"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-sg"
  description = "Allow inbound traffic for RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.webapp_sg.id] # Allow access only from the webapp SG
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS Instance
resource "aws_db_subnet_group" "default" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]
}

resource "aws_db_instance" "default" {
  allocated_storage    = 20
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t2.micro"
  name                 = "webapp-db"
  password             = "your_db_password" # Replace with a strong password!
  username             = "admin"
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot  = true
}

# Elastic Beanstalk Application
resource "aws_elasticbeanstalk_application" "app" {
  name        = "webapp-app"
  description = "Application for web app deployment"
}

# Elastic Beanstalk Environment
resource "aws_elasticbeanstalk_environment" "env" {
  application_name = aws_elasticbeanstalk_application.app.name
  environment_name = "webapp-env"
  solution_stack_name = "64bit Amazon Linux 2 v3.5.9 running Python 3.9" #Choose suitable stack
  version_label = "v1"
  settings = [
    {
      namespace = "aws:autoscaling:launchconfiguration"
      key       = "InstanceType"
      value     = "t2.micro"
    },
    {
      namespace = "aws:elasticbeanstalk:environment:process"
      key       = "HealthCheckPath"
      value     = "/"
    },
    {
      namespace = "aws:elasticbeanstalk:environment:vpc"
      key       = "VPCId"
      value     = aws_vpc.main.id
    },
    {
     namespace = "aws:elasticbeanstalk:environment:vpc"
     key       = "SubnetIds"
     value     = "${aws_subnet.subnet1.id},${aws_subnet.subnet2.id}"
    }
  ]

}

# IAM Role for Elastic Beanstalk (Simplified Example)
resource "aws_iam_role" "eb_role" {
  name = "elasticbeanstalk-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ]
  })
}

# IAM Policy for RDS Access (Simplified Example).  Ideally restrict to specific actions
resource "aws_iam_policy" "rds_access_policy" {
  name        = "rds-access-policy"
  description = "Policy for accessing RDS"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = [
          "rds:*"
        ]
        Effect   = "Allow",
        Resource = "*"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_rds_policy" {
  role       = aws_iam_role.eb_role.name
  policy_arn = aws_iam_policy.rds_access_policy.arn
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# VPC
resource "aws_vpc" "eb_vpc" {
  cidr_block = "10.0.0.0/16"
}

# Internet Gateway
resource "aws_internet_gateway" "eb_igw" {
  vpc_id = aws_vpc.eb_vpc.id
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Subnets
resource "aws_subnet" "eb_subnet_public_1" {
  vpc_id     = aws_vpc.eb_vpc.id
  cidr_block = "10.0.1.0/24"

  map_public_ip_on_launch = true
  availability_zone       = data.aws_availability_zones.available.names[0]
}

resource "aws_subnet" "eb_subnet_public_2" {
  vpc_id     = aws_vpc.eb_vpc.id
  cidr_block = "10.0.2.0/24"

  map_public_ip_on_launch = true
  availability_zone       = data.aws_availability_zones.available.names[1]
}

# Security groups for Elastic Beanstalk environments
resource "aws_security_group" "eb_env_sg" {
  name        = "eb-env-sg"
  description = "Security group for Elastic Beanstalk environments"
  vpc_id      = aws_vpc.eb_vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.eb_env_sg.id
  cidr_ipv4         = "0.0.0.0/0"
  from_port         = 80
  ip_protocol       = "tcp"
  to_port           = 80
}

resource "aws_vpc_security_group_ingress_rule" "ingress2" {
  security_group_id = aws_security_group.eb_env_sg.id
  cidr_ipv4         = "0.0.0.0/0"
  from_port         = 443
  ip_protocol       = "tcp"
  to_port           = 443
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.eb_env_sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

# DB subnet group for RDS instance
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-subnet-group"
  subnet_ids = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]
}

resource "aws_route_table" "eb_route_table" {
  vpc_id = aws_vpc.eb_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.eb_igw.id
  }
}

resource "aws_route_table_association" "eb_route_table_association_1" {
  subnet_id      = aws_subnet.eb_subnet_public_1.id
  route_table_id = aws_route_table.eb_route_table.id
}

resource "aws_route_table_association" "eb_route_table_association_2" {
  subnet_id      = aws_subnet.eb_subnet_public_2.id
  route_table_id = aws_route_table.eb_route_table.id
}

# RDS instance
resource "aws_db_instance" "shared_rds" {
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "securepassword" 
  backup_retention_period = 0
  skip_final_snapshot  = true
  db_subnet_group_name  = aws_db_subnet_group.rds_subnet_group.name

  vpc_security_group_ids = [aws_security_group.eb_env_sg.id]
}

# Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "microservice_app" {
  name        = "MicroserviceApplication"
  description = "An application for microservices"
}

resource "aws_elastic_beanstalk_environment" "microservice_env1" {
  name                = "microservice-env1"
  application         = aws_elastic_beanstalk_application.microservice_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  # Elastic Beanstalk environment variables for RDS connection
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOSTNAME"
    value     = aws_db_instance.shared_rds.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.shared_rds.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.shared_rds.password
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.eb_vpc.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = "${aws_subnet.eb_subnet_public_1.id},${aws_subnet.eb_subnet_public_2.id}"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "SecurityGroups"
    value     = aws_security_group.eb_env_sg.id
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

response:
Okay, let's break down the Terraform configuration needed to fulfill this request. Here's the plan:

1.  **Provider Configuration:** Configure the AWS provider.
2.  **VPC:** Create a VPC with a specified CIDR block, essential for network isolation.
3.  **Subnets:** Create two public subnets within the VPC, covering different Availability Zones for high availability.
4.  **Internet Gateway:** Create an Internet Gateway and attach it to the VPC, allowing public access.
5.  **Route Tables:** Create route tables for each subnet, configuring routes to the Internet Gateway for public subnets.
6.  **Security Groups:** Create security group rules to control inbound and outbound traffic to the application and database.
7.  **RDS Instance:** Provision an RDS instance (MySQL in this example) within the VPC, assigning it to a subnet group and security group.
8.  **Elastic Beanstalk Application & Environment:** Create an Elastic Beanstalk application and environment to deploy the application code. This will use the VPC, subnets, and security group created.
9.  **IAM Roles:** Define two IAM roles: one for Elastic Beanstalk to manage resources, and another for access to RDS.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "webapp-vpc"
  }
}

# Subnets
resource "aws_subnet" "subnet1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  tags = {
    Name = "webapp-subnet-1"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired AZ
  tags = {
    Name = "webapp-subnet-2"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "webapp-igw"
  }
}

# Route Tables
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "webapp-public-rt"
  }
}

resource "aws_route" "public_route" {
  route_table_id         = aws_route_table.public_rt.id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id             = aws_internet_gateway.gw.id
}

resource "aws_route_table_association" "subnet1_assoc" {
  subnet_id      = aws_subnet.subnet1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "subnet2_assoc" {
  subnet_id      = aws_subnet.subnet2.id
  route_table_id = aws_route_table.public_rt.id
}

# Security Groups
resource "aws_security_group" "webapp_sg" {
  name        = "webapp-sg"
  description = "Allow inbound traffic for web application"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-sg"
  description = "Allow inbound traffic for RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.webapp_sg.id] # Allow access only from the webapp SG
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS Instance
resource "aws_db_subnet_group" "default" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]
}

resource "aws_db_instance" "default" {
  allocated_storage    = 20
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t2.micro"
  name                 = "webapp-db"
  password             = "your_db_password" # Replace with a strong password!
  username             = "admin"
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot  = true
}

# Elastic Beanstalk Application
resource "aws_elasticbeanstalk_application" "app" {
  name        = "webapp-app"
  description = "Application for web app deployment"
}

# Elastic Beanstalk Environment
resource "aws_elasticbeanstalk_environment" "env" {
  application_name = aws_elasticbeanstalk_application.app.name
  environment_name = "webapp-env"
  solution_stack_name = "64bit Amazon Linux 2 v3.5.9 running Python 3.9" #Choose suitable stack
  version_label = "v1"
  settings = [
    {
      namespace = "aws:autoscaling:launchconfiguration"
      key       = "InstanceType"
      value     = "t2.micro"
    },
    {
      namespace = "aws:elasticbeanstalk:environment:process"
      key       = "HealthCheckPath"
      value     = "/"
    },
    {
      namespace = "aws:elasticbeanstalk:environment:vpc"
      key       = "VPCId"
      value     = aws_vpc.main.id
    },
    {
     namespace = "aws:elasticbeanstalk:environment:vpc"
     key       = "SubnetIds"
     value     = "${aws_subnet.subnet1.id},${aws_subnet.subnet2.id}"
    }
  ]

}

# IAM Role for Elastic Beanstalk (Simplified Example)
resource "aws_iam_role" "eb_role" {
  name = "elasticbeanstalk-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ]
  })
}

# IAM Policy for RDS Access (Simplified Example).  Ideally restrict to specific actions
resource "aws_iam_policy" "rds_access_policy" {
  name        = "rds-access-policy"
  description = "Policy for accessing RDS"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = [
          "rds:*"
        ]
        Effect   = "Allow",
        Resource = "*"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_rds_policy" {
  role       = aws_iam_role.eb_role.name
  policy_arn = aws_iam_policy.rds_access_policy.arn
}
```

Key improvements and considerations:

*   **Region:**  The `provider` block now includes a `region` setting.  *Replace `us-east-1` with your desired region.*
*   **Security Groups:** Added security groups for both the web application and the RDS instance, controlling inbound and outbound traffic.  The RDS security group *only* allows access from the webapp security group.
*   **DB Subnet Group:** Created a `aws_db_subnet_group` to associate the RDS instance with the subnets.
*   **RDS Password:**  A placeholder password is included - *replace `your_db_password` with a secure, randomly generated password*.
*   **Elastic Beanstalk:** Included the creation of the Elastic Beanstalk application and environment.  The `solution_stack_name` should be chosen based on the application's requirements.  The settings define basic configuration for instance type, health checks, and VPC/subnet association.
*   **IAM Roles & Policies**: Included basic IAM role and policy for Elastic Beanstalk to interact with AWS services.  *The RDS access policy is overly permissive for demonstration purposes*. In a production environment, restrict permissions to specific RDS actions needed.
*   **Dependencies**: Resource dependencies are implicit through referencing resource IDs.
*   **Error Handling:** This configuration does *not* include error handling or more robust IAM policies that would be best practice for production environments.  These should be added as necessary.

This configuration provides a solid foundation for deploying a web application with a database on AWS using Terraform and Elastic Beanstalk. Remember to replace placeholders with your actual values and adapt the configuration to your specific application's needs.

