}

# Replace with your actual domain name
variable "domain_name" {
  type        = string
  description = "The domain name to manage in Route 53"
  default     = "example.com"
}

# Elastic Beanstalk Instance Profile Name
variable "instance_profile_name" {
  type        = string
  description = "The name of the Elastic Beanstalk instance profile"
  default     = "eb_ec2_profile1"
}

# The CNAME for the Elastic Beanstalk environment.
variable "eb_cname" {
  type        = string
  description = "The CNAME of the Elastic Beanstalk environment."
  default     = "myenv.elasticbeanstalk.com"
}

# Create a Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = var.domain_name
}

# Create a Route 53 record to point to the Elastic Beanstalk environment.
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.${var.domain_name}" # Assuming a www subdomain. Change if needed.
  type    = "CNAME"
  ttl     = "300"
  records = [var.eb_cname]
}

#Elastic Beanstalk configuration
resource "aws_elasticbeanstalk_environment" "myenv" {
