}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}


# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Create the RDS database used by both the blue and green environments
resource "aws_db_instance" "myapp_db" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  username             = "myappuser"
  password             = "mysecurepassword"
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true
}

# Create an Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "myapp" {
  name        = "my-app"
  description = "My application"
}

# Blue environment
resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "my-app-blue"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  # Example setting to connect to the RDS instance
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.myapp_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.myapp_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.myapp_db.password
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Green environment (new version)
resource "aws_elastic_beanstalk_environment" "green" {
  name                = "my-app-green"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.myapp_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.myapp_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.myapp_db.password
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# DNS setup with Route 53
resource "aws_route53_zone" "myapp_zone" {
  name = "myapp.com"
}

# Health check for blue environment
resource "aws_route53_health_check" "blue" {
  fqdn              = aws_elastic_beanstalk_environment.blue.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
}

# Health check for green environment
resource "aws_route53_health_check" "green" {
  fqdn              = aws_elastic_beanstalk_environment.green.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
}

# Record set for the blue environment
resource "aws_route53_record" "blue" {
  zone_id = aws_route53_zone.myapp_zone.zone_id
  name    = "blue.myapp.com"
  type    = "CNAME"
  ttl     = "5"
  records = [aws_elastic_beanstalk_environment.blue.cname]
  set_identifier = "BlueEnv"
  failover_routing_policy {
    type = "PRIMARY"
  }
  health_check_id = aws_route53_health_check.blue.id
}

# Record set for the green environment using CNAME
resource "aws_route53_record" "green" {
  zone_id = aws_route53_zone.myapp_zone.zone_id
  name    = "green.myapp.com"
  type    = "CNAME"
  ttl     = "5"
  records = [aws_elastic_beanstalk_environment.green.cname]
  set_identifier = "greenEnv"
  failover_routing_policy {
    type = "SECONDARY"
  }
  health_check_id = aws_route53_health_check.green.id
}

response:
Okay, let's break down this request and outline a Terraform configuration.

1.  **RDS Instance:** We need a shared RDS instance. This will be the core of both environments. We'll define this first.
2.  **EC2 Instances (Blue & Green):** Two sets of EC2 instances, one for "blue" and one for "green", will be created.  These will connect to the RDS database.  For simplicity, we'll just define basic instances here. Ideally a more full configuration would involve auto-scaling groups etc, but we'll keep it minimal for the request.
3.  **Route 53 Hosted Zone:**  A Route 53 hosted zone is necessary to manage DNS records.
4.  **Route 53 Records (Blue & Green):** Two records will be created in the hosted zone - one for "blue" and one for "green". They will point to the respective EC2 instance public IPs.
5.  **Health Checks:**  Route 53 health checks will be configured to monitor the EC2 instances in both environments. Without health checks, the failover policy won't work correctly.
6.  **Failover Routing Policy:** The Route 53 records will use a failover routing policy. We'll configure Blue as the primary and Green as the secondary.
7.  **IAM Role for EC2:** An IAM role to provide the EC2 instances with needed permissions. The instance profile is named "eb\_ec2\_profile".

Here's the Terraform code reflecting these steps:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Replace with your desired region
}

# 1. RDS Instance
resource "aws_db_instance" "myapp_db" {
  allocated_storage    = 20
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  name                 = "myapp_db"
  username             = "admin"
  password             = "your_password" # Replace with a strong password
  db_subnet_group_name = aws_db_subnet_group.default.name
  skip_final_snapshot  = true
}

resource "aws_db_subnet_group" "default" {
  name       = "myapp-subnet-group"
  subnet_ids = [
    "subnet-xxxxxxxxxxxxxxxxx", # Replace with your subnet IDs
    "subnet-yyyyyyyyyyyyyyyyy", # Replace with your subnet IDs
  ]
}


# 2. EC2 Instances (Blue & Green)
resource "aws_instance" "blue" {
  ami           = "ami-0c55b05017c2fc257" # Replace with a suitable AMI
  instance_type = "t2.micro"
  key_name      = "your_key_pair" # Replace with your key pair
  tags = {
    Name = "myapp-blue"
  }
}

resource "aws_instance" "green" {
  ami           = "ami-0c55b05017c2fc257" # Replace with a suitable AMI
  instance_type = "t2.micro"
  key_name      = "your_key_pair" # Replace with your key pair
  tags = {
    Name = "myapp-green"
  }
}


# 3. Route 53 Hosted Zone
resource "aws_route53_zone" "myapp_zone" {
  name = "myapp.example.com"   # Replace with your domain name
}

# 4. Route 53 Records (Blue & Green)
resource "aws_route53_record" "blue_record" {
  zone_id = aws_route53_zone.myapp_zone.zone_id
  name    = "www.myapp.example.com" # Replace if needed
  type    = "A"
  set_identifier = "blue"

  failover_routing_policy {
    type = "FAILOVER"
    priority = 10
  }

  records = [aws_instance.blue.public_ip]
  health_check_id = aws_route53_health_check.blue_health_check.id

}

resource "aws_route53_record" "green_record" {
  zone_id = aws_route53_zone.myapp_zone.zone_id
  name    = "www.myapp.example.com" # Replace if needed
  type    = "A"
  set_identifier = "green"

  failover_routing_policy {
    type = "FAILOVER"
    priority = 20
  }

  records = [aws_instance.green.public_ip]
  health_check_id = aws_route53_health_check.green_health_check.id
}

# 5. Health Checks
resource "aws_route53_health_check" "blue_health_check" {
  name             = "blue-health-check"
  type             = "HTTP"
  request_interval = 30
  failure_threshold = 3
  port             = 80 # Or the correct port for your application
  path             = "/"
  fqdn             = aws_instance.blue.public_dns
}

resource "aws_route53_health_check" "green_health_check" {
  name             = "green-health-check"
  type             = "HTTP"
  request_interval = 30
  failure_threshold = 3
  port             = 80 # Or the correct port for your application
  path             = "/"
  fqdn             = aws_instance.green.public_dns
}

# 6. IAM Instance profile
resource "aws_iam_role" "eb_ec2_profile" {
  name               = "eb_ec2_profile"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

```

Important considerations:

*   **Replace Placeholders:** Fill in the placeholder values (region, AMI ID, key pair name, database password, subnet IDs, domain name, etc.).
*   **Security Groups:**  This configuration doesn't include security groups. You'll need to add appropriate security group rules to allow traffic to the EC2 instances and RDS database.
*   **Networking:** Subnet IDs are critical for the RDS instance.
*   **RDS Configuration:** Consider more robust RDS configurations such as multi-AZ deployments for improved availability.
*   **Monitoring & Scaling**: Implement proper monitoring using CloudWatch and consider Auto Scaling Groups (ASGs) to scale instances based on demand.
*   **Deployment Automation**: This setup provides the infrastructure. You will still need a separate process (e.g., CI/CD pipeline) to deploy your application code to the EC2 instances in the blue and green environments.
*   **Production Readiness**: This example is simplified.  A production environment would require more comprehensive security measures, monitoring, and scaling configurations.
*   **Health Check Endpoint**: Ensure that the health check `/` path is correct for your application. It must return a 200 OK status code if the application is healthy.

