  environment_type    = "SingleInstance" # Or 'LoadBalanced'

  settings = [
    {
      namespace = "aws:elasticbeanstalk:environment"
      setting_name = "EnvironmentType"
      setting_value = "SingleInstance"
    },
     {
      namespace = "aws:elasticbeanstalk:environment:process"
      setting_name = "HealthCheckPath"
      setting_value = "/"
    }
  ]

  depends_on = [
    aws_elasticbeanstalk_application_version.app_version,
    aws_iam_role_policy_attachment.beanstalk_policy_attachment
  ]

}
