Okay, let's break down the requirements to create an AWS CodeBuild project with an example IAM role and secondary sources.

1.  **CodeBuild Project:** We need to define a `aws_codebuild_project` resource. This will include settings like the project name, source code location (e.g., a GitHub repository), buildspec file, environment (compute resources), and artifacts.
2.  **IAM Role:**  We will define an IAM role specifically for CodeBuild. This role needs permissions allowing it to pull code from the source repository, access other AWS services as dictated by the buildspec, and write build artifacts.  We'll create a `aws_iam_role` and `aws_iam_policy`.
3.  **Secondary Sources:** The configuration should include secondary source code repositories that CodeBuild can utilize during the build process. We define those using the `secondary_source` block within the CodeBuild project.  Important: The secondary source also needs the IAM permissions to access it.

Here's the Terraform configuration:

```hcl
resource "aws_iam_role" "codebuild_role" {
  name               = "codebuild_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com",
        },
        Effect = "Allow",
        Sid    = "",
      },
    ],
  })
}

resource "aws_iam_policy" "codebuild_policy" {
  name        = "codebuild_policy"
  description = "Policy for CodeBuild"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:Get*",
          "s3:Put*",
          "s3:Delete*",
          "s3:List*",
        ],
        Effect   = "Allow",
        Resource = [
          "arn:aws:s3:::your-codebuild-bucket/*", # Replace with your S3 bucket
        ],
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
        ],
        Effect   = "Allow",
        Resource = "arn:aws:logs:*:*:log-group:/aws/codebuild/*",
      },
      {
        Action = [
          "codecommit:GitPull",
        ],
        Effect   = "Allow",
        Resource = [
          "arn:aws:codecommit:*:*:your-codecommit-repo",  #Replace with your codecommit repo
        ],
      },
    ],
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_role_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}


resource "aws_codebuild_project" "example" {
  name         = "example-codebuild-project"
  description  = "An example CodeBuild project"

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-github-org/your-github-repo.git" # Replace with your github repo
    branch    = "main"
  }

  secondary_source {
    type      = "GITHUB"
    location  = "https://github.com/your-github-org/your-secondary-repo.git" #Replace with secondary repo
    branch    = "main"
  }


  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX"
  }

  role_arn = aws_iam_role.codebuild_role.arn
}
```

