response:
:
Okay, let's break down the requirements to create an AWS CodeBuild project with Terraform. We need to define:

1.  **CodeBuild Project:** The core resource, including name, source provider, buildspec, and service role.
2.  **IAM Role:**  An IAM role for CodeBuild to assume permissions. This role needs permissions to access source code (e.g., CodeCommit, S3, GitHub), CloudWatch Logs, and potentially other resources depending on the build process. I will create a basic role with essential permissions.
3.  **Environment Variables:** A set of environment variables that CodeBuild will make available during builds.
4.  **Secondary Sources:**  Additional code repositories or S3 buckets that CodeBuild will use as input.
5.  **Secondary Artifacts:** Define additional artifacts generated during the build process, like test reports or documentation.

Here's the Terraform configuration:

```hcl
resource "aws_iam_role" "codebuild_role" {
  name               = "codebuild-role"
  description        = "IAM role for CodeBuild"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Effect = "Allow"
        Sid    = ""
      },
    ]
  })

  inline_policy {
    name = "codebuild-policy"
    document = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Action = [
            "logs:CreateLogGroup",
            "logs:CreateLogStream",
            "logs:PutLogEvents"
          ]
          Effect   = "Allow"
          Resource = "arn:aws:logs:*:*:*"
        },
        {
          Action = [
            "s3:GetObject",
            "s3:GetObjectVersion"
          ]
          Effect   = "Allow"
          Resource = "arn:aws:s3:::*" # Restrict to specific buckets in production
        },
        {
          Action = [
            "s3:PutObject",
            "s3:PutObjectAcl"
          ]
          Effect   = "Allow"
          Resource = "arn:aws:s3:::*" # Restrict to specific buckets in production
        },
      ]
    })
  }
}

resource "aws_codebuild_project" "example" {
  name         = "example-codebuild-project"
  description  = "Example CodeBuild project"
  service_role = aws_iam_role.codebuild_role.arn

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-repo/your-project" # Replace with your repo URL
    git_clone_depth = 10
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX"
    environment_variables = {
      "MY_ENVIRONMENT_VARIABLE" = "my_value"
      "ANOTHER_VARIABLE"        = "another_value"
    }
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  secondary_sources {
    name = "secondary-source"
    type = "GITHUB"
    location = "https://github.com/secondary-repo/secondary-project" # Replace with your secondary repo
    git_clone_depth = 10
  }

  secondary_artifacts {
    name = "secondary-artifact"
    type = "NO_ARTIFACTS"
  }

  logs_config {
      cloudwatch_logs {
        group_name = "/aws/codebuild/example-codebuild-project"
        stream_name = "example-codebuild-project-log-stream"
      }
  }
}
```

