}

# IAM Role for Lex to invoke Lambda
resource "aws_iam_role" "lex_lambda_role" {
  name               = "lex_lambda_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lex.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ],
  })
}

resource "aws_iam_policy" "lex_lambda_policy" {
  name        = "lex_lambda_policy"
  description = "Policy to allow Lex to invoke Lambda"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = "lambda:InvokeFunction",
        Effect   = "Allow",
        Resource = "${aws_lambda_function.pizza_order_lambda.arn}"
      },
    ],
  })
}

resource "aws_iam_role_policy_attachment" "lex_lambda_attachment" {
  role       = aws_iam_role.lex_lambda_role.name
  policy_arn = aws_iam_policy.lex_lambda_policy.arn
}


# Lambda Function
resource "aws_lambda_function" "pizza_order_lambda" {
  function_name = "pizzaOrderLambda"
  role          = aws_iam_role.lex_lambda_role.arn
  handler       = "lambda_function.lambda_handler"
  runtime       = "python3.9"

  zip_file = file("lambda_function.zip") # Replace with the path to your zipped Lambda function code
}

# Lex Bot
resource "aws_lex_bot" "pizza_bot" {
  name             = "PizzaOrderBot"
  idle_session_timeout_in_minutes = 5
  voice_role_arn   = "arn:aws:lex:us-east-1:123456789012:voiceRole/Amazon Polly Neural TTS" # Replace with your desired voice role ARN, if needed

  intents = [
    {
      name = "OrderPizza"
      slots = [
        {
          name = "pizzaType"
          slot_constraint = "Required"
          slot_type = "AMAZON.PizzaType"
          value_elicitation_prompt {
            messages = [
              {
                content = "What kind of pizza would you like to order?"
              },
            ]
          }
        },
      ]
      sample_utterances = [
        "I want to order a {pizzaType}",
        "Order a {pizzaType} pizza",
      ]
      fulfillment_activity {
        type = "Lambda"
        settings {
          code_hook {
            uri = aws_lambda_function.pizza_order_lambda.invoke_arn
            message_version = "1.0"
          }
        }
      }
    },
  ]
}

# Lex Bot Alias
resource "aws_lex_bot_alias" "pizza_bot_alias" {
  name        = "test"
  bot_name    = aws_lex_bot.pizza_bot.name
  bot_version = "$LATEST"
}

