    intent_version = aws_lex_intent.OrderPizza.version
  }

  # depends_on = [aws_lambda_permission.allow_lex_to_start_execution]
}

response:
Okay, let's break this down. We need to create an AWS Lex bot and link it to a Lambda function. Here's the plan:

1.  **AWS Provider:** First, configure the AWS provider.
2.  **IAM Role for Lex:**  Lex needs permissions to invoke the Lambda function. We'll create an IAM role for this purpose.
3.  **Lambda Function:**  We'll define a simple Lambda function (in this example, a placeholder) to handle the Lex bot's input.  I will include a basic Python function that simply returns a confirmation message.
4.  **Lex Bot:** We'll define the `aws_lex_bot` resource, including its name, idle session timeout, voice role, and intent configurations.  We'll configure a basic intent and associate it with the Lambda function.
5.  **Lex Bot Alias** Create a bot alias to publish the bot.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# IAM Role for Lex to invoke Lambda
resource "aws_iam_role" "lex_lambda_role" {
  name               = "lex_lambda_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lex.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ],
  })
}

resource "aws_iam_policy" "lex_lambda_policy" {
  name        = "lex_lambda_policy"
  description = "Policy to allow Lex to invoke Lambda"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = "lambda:InvokeFunction",
        Effect   = "Allow",
        Resource = "${aws_lambda_function.pizza_order_lambda.arn}"
      },
    ],
  })
}

resource "aws_iam_role_policy_attachment" "lex_lambda_attachment" {
  role       = aws_iam_role.lex_lambda_role.name
  policy_arn = aws_iam_policy.lex_lambda_policy.arn
}


# Lambda Function
resource "aws_lambda_function" "pizza_order_lambda" {
  function_name = "pizzaOrderLambda"
  role          = aws_iam_role.lex_lambda_role.arn
  handler       = "lambda_function.lambda_handler"
  runtime       = "python3.9"

  zip_file = file("lambda_function.zip") # Replace with the path to your zipped Lambda function code
}

# Lex Bot
resource "aws_lex_bot" "pizza_bot" {
  name             = "PizzaOrderBot"
  idle_session_timeout_in_minutes = 5
  voice_role_arn   = "arn:aws:lex:us-east-1:123456789012:voiceRole/Amazon Polly Neural TTS" # Replace with your desired voice role ARN, if needed

  intents = [
    {
      name = "OrderPizza"
      slots = [
        {
          name = "pizzaType"
          slot_constraint = "Required"
          slot_type = "AMAZON.PizzaType"
          value_elicitation_prompt {
            messages = [
              {
                content = "What kind of pizza would you like to order?"
              },
            ]
          }
        },
      ]
      sample_utterances = [
        "I want to order a {pizzaType}",
        "Order a {pizzaType} pizza",
      ]
      fulfillment_activity {
        type = "Lambda"
        settings {
          code_hook {
            uri = aws_lambda_function.pizza_order_lambda.invoke_arn
            message_version = "1.0"
          }
        }
      }
    },
  ]
}

# Lex Bot Alias
resource "aws_lex_bot_alias" "pizza_bot_alias" {
  name        = "test"
  bot_name    = aws_lex_bot.pizza_bot.name
  bot_version = "$LATEST"
}
```

**Important Considerations:**

*   **Lambda Code:**  You'll need to create a `lambda_function.py` file (or similar, depending on your runtime) and zip it.  The example includes a placeholder `lambda_function.zip`. The content of the file should be similar to:

```python
import json

def lambda_handler(event, context):
  return {
    'statusCode': 200,
    'body': json.dumps('Your pizza order has been received!')
  }

```

*   **Region:**  Replace `"us-east-1"` with the AWS region you're using.
*   **Voice Role ARN:** Replace the example `voice_role_arn` with a valid ARN for a voice role in your AWS account. If you don't specify one, it will use the default.
*   **Slot Types:** Adjust the `slot_type` values (e.g., `AMAZON.PizzaType`) to match the built-in or custom slot types you define in Lex.
*   **Sample Utterances:**  Add more variations to the `sample_utterances` to improve bot understanding.
*   **IAM Permissions**: Ensure your AWS account has appropriate permissions to create these resources, and the Lambda role has permission to execute.
* **Error Handling**: In a production environment, incorporate robust error handling and logging into your Lambda function.
*   **Lex Console:** While Terraform creates the base bot, you'll likely need to use the AWS Lex console to refine the bot's behavior, add more intents, and improve conversational flow.
*   **Zip File:** Ensure that lambda\_function.zip exists in the same directory as your terraform configuration, and contains your lambda function code.

