  }
}

# 2. IAM Role for Kinesis Data Analytics
resource "aws_iam_role" "kinesis_analytics_role" {
  name               = "kinesis-analytics-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ],
