resource "aws_iam_policy" "kinesis_analytics_policy" {
  name        = "kinesis-analytics-policy"
  description = "Policy for Kinesis Data Analytics to access Kinesis and S3"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "kinesis:GetRecords",
          "kinesis:GetShardIterator",
          "kinesis:DescribeStream",
          "kinesis:ListShards"
        ],
        Effect   = "Allow",
        Resource = "*" # Consider restricting to specific stream ARNs in production
      },
      {
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
