      {
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
          "${aws_s3_bucket.flink_app_bucket.arn}",
          "${aws_s3_bucket.flink_app_bucket.arn}/*",
        ],
