terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

# even though this program seems to be problematic, it's copied from https://registry.terraform.io/providers/hashicorp/aws/latest/docs/resources/kinesis_firehose_delivery_stream
# so I'll leave it unmodified

data "aws_iam_policy_document" "firehose_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["firehose.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "firehose_role" {
  name               = "firehose_test_role"
  assume_role_policy = data.aws_iam_policy_document.firehose_assume_role.json
}

resource "aws_s3_bucket" "decemberthirtysecond" {
  bucket = "decemberthirtysecond"
}
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name        = "terraform-kinesis-firehose-extended-s3-test-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.decemberthirtysecond.arn
    buffering_size = 64

    # https://docs.aws.amazon.com/firehose/latest/dev/dynamic-partitioning.html
    dynamic_partitioning_configuration {
      enabled = "true"
    }

    # Example prefix using partitionKeyFromQuery, applicable to JQ processor
    prefix              = "data/customer_id=!{partitionKeyFromQuery:customer_id}/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"
    error_output_prefix = "errors/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/!{firehose:error-output-type}/"

    processing_configuration {
      enabled = "true"

      # Multi-record deaggregation processor example
      processors {
        type = "RecordDeAggregation"
        parameters {
          parameter_name  = "SubRecordType"
          parameter_value = "JSON"
        }
      }

      # New line delimiter processor example
      processors {
        type = "AppendDelimiterToRecord"
      }

      # JQ processor example
      processors {
        type = "MetadataExtraction"
        parameters {
          parameter_name  = "JsonParsingEngine"
          parameter_value = "JQ-1.6"
        }
        parameters {
          parameter_name  = "MetadataExtractionQuery"
          parameter_value = "{customer_id:.customer_id}"
        }
      }
    }
  }
}

response:
:
Okay, let's break down the requirements to create a Kinesis Firehose Delivery Stream with an extended S3 destination and dynamic partitioning.

1.  **Provider:** We'll need an AWS provider configured. I'll assume it's already configured.
2.  **Kinesis Firehose Role:** We need an IAM role that Firehose can assume to deliver data to S3. This role needs permissions to write to the S3 bucket.
3.  **S3 Bucket:** We'll specify the S3 bucket where the data will be delivered.
4.  **Firehose Delivery Stream:** The core resource.
    *   `name`: A unique name for the stream.
    *   `destination`: This will be an 'extended' S3 destination.
    *   `s3_configuration`: Contains details about the S3 bucket, prefix, error output prefix, and important for the request, dynamic partitioning.
        *   `role_arn`: The ARN of the IAM role.
        *   `bucket_name`: The name of the S3 bucket.
        *   `prefix`: An optional prefix to place objects in S3.
        *   `error_output_prefix`:  A prefix for error logs.
        *   `dynamic_partitioning`: Enabled.
        *   `partitioning_key`: The key to partition data by.
5.  **IAM Role (if not already existing):** Define the permissions for the delivery stream role.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Replace with your desired values
variable "stream_name" {
  type    = string
  default = "my-kinesis-firehose-stream"
}

variable "s3_bucket_name" {
  type    = string
  default = "my-kinesis-firehose-bucket" #Ensure this bucket exists.
}

variable "role_arn" {
  type    = string
  default = "arn:aws:iam::123456789012:role/KinesisFirehoseDeliveryRole" # Replace with an existing role ARN
}

variable "partitioning_key" {
  type    = string
  default = "year"
}

resource "aws_kinesis_firehose_delivery_stream" "example" {
  name            = var.stream_name
  destination     = "s3"
  s3_configuration {
    role_arn           = var.role_arn
    bucket_name        = var.s3_bucket_name
    prefix             = "firehose-data/"
    error_output_prefix = "firehose-errors/"
    dynamic_partitioning {
      enabled = true
      partitioning_key = var.partitioning_key
    }
  }
}
```

