# IAM Role for Firehose to access Redshift and Kinesis
resource "aws_iam_role" "firehose_role" {
  name               = "firehose-redshift-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "firehose.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })

  tags = {
    Name = "firehose-redshift-role"
  }
}

resource "aws_iam_policy" "firehose_policy" {
  name        = "firehose-redshift-policy"
  description = "Policy for Firehose to access Kinesis and Redshift"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "firehose:PutRecord",
          "firehose:DescribeDeliveryStream",
        ],
        Resource = "*",
        Effect   = "Allow"
      },
      {
        Action = [
          "redshift:BatchLoad",
          "redshift:DescribeCluster",
        ],
        Resource = "*", # Replace with your Redshift cluster ARN
        Effect   = "Allow"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attachment" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

# IAM Role for Redshift to allow Firehose to load data
