terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "bucket" {
  bucket_prefix = "my-bucket-"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Subnets
resource "aws_subnet" "first" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  map_public_ip_on_launch = true
  availability_zone       = data.aws_availability_zones.available.names[0]
}

resource "aws_subnet" "second" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"

  map_public_ip_on_launch = true
  availability_zone       = data.aws_availability_zones.available.names[1]
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.first.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.second.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "first" {
  name        = "test-security-group"
  description = "Allow traffic for Elasticsearch"
  vpc_id      = aws_vpc.main.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.first.id
  cidr_ipv4 = "0.0.0.0/0"
  from_port = 80
  ip_protocol = "tcp"
  to_port = 80
}

resource "aws_vpc_security_group_ingress_rule" "ingress2" {
  security_group_id = aws_security_group.first.id
  cidr_ipv4 = "0.0.0.0/0"
  from_port = 443
  ip_protocol = "tcp"
  to_port = 443
}

resource "aws_vpc_security_group_ingress_rule" "ingress3" {
  security_group_id = aws_security_group.first.id
  cidr_ipv4 = "0.0.0.0/0"
  from_port = 9200
  ip_protocol = "tcp"
  to_port = 9200
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.first.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_elasticsearch_domain" "test_cluster" {
  domain_name = "es-test"

  cluster_config {
    instance_count         = 2
    zone_awareness_enabled = true
    instance_type          = "t2.small.elasticsearch"
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  vpc_options {
    security_group_ids = [aws_security_group.first.id]
    subnet_ids         = [aws_subnet.first.id, aws_subnet.second.id]
  }
}

data "aws_iam_policy_document" "firehose_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["firehose.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "firehose_role" {
  name               = "firehose_test_role"
  assume_role_policy = data.aws_iam_policy_document.firehose_assume_role.json
}

data "aws_iam_policy_document" "firehose-elasticsearch" {
  statement {
    effect  = "Allow"
    actions = ["es:*"]

    resources = [
      aws_elasticsearch_domain.test_cluster.arn,
      "${aws_elasticsearch_domain.test_cluster.arn}/*",
    ]
  }

  statement {
    effect = "Allow"

    actions = [
      "ec2:DescribeVpcs",
      "ec2:DescribeVpcAttribute",
      "ec2:DescribeSubnets",
      "ec2:DescribeSecurityGroups",
      "ec2:DescribeNetworkInterfaces",
      "ec2:CreateNetworkInterface",
      "ec2:CreateNetworkInterfacePermission",
      "ec2:DeleteNetworkInterface",
    ]

    resources = ["*"]
  }
}

resource "aws_iam_role_policy" "firehose-elasticsearch" {
  name   = "elasticsearch"
  role   = aws_iam_role.firehose_role.id
  policy = data.aws_iam_policy_document.firehose-elasticsearch.json
}

resource "aws_kinesis_firehose_delivery_stream" "test" {
  depends_on = [aws_iam_role_policy.firehose-elasticsearch]

  name        = "terraform-kinesis-firehose-es"
  destination = "elasticsearch"

  elasticsearch_configuration {
    domain_arn = aws_elasticsearch_domain.test_cluster.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "test"
    type_name  = "test"

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.bucket.arn
    }

    vpc_config {
      subnet_ids         = [aws_subnet.first.id, aws_subnet.second.id]
      security_group_ids = [aws_security_group.first.id]
      role_arn           = aws_iam_role.firehose_role.arn
    }
  }
}

response:
: Okay, let's break down the requirements and then generate the Terraform configuration.

1. **Kinesis Firehose Delivery Stream:** We need to define a `aws_kinesis_firehose_delivery_stream` resource.  This will be the core of the configuration.

2. **Elasticsearch Destination:** The destination type will be `Elasticsearch`. This means we need to provide Elasticsearch configuration details within the delivery stream definition, like the domain ARN, index name configuration, and buffering hints.

3. **VPC Configuration:** Since the request specifically mentions "With VPC," we need to configure VPC network access for Firehose. To do this, we'll use the `vpc_configuration` block and specify a subnet and security group.

4. **IAM Role:** Kinesis Firehose requires an IAM role to access other AWS services (S3, Elasticsearch, etc.). We'll need an `aws_iam_role` and `aws_iam_policy` to grant the necessary permissions.

5. **Tags:** Adding tags is good practice.

Here's the Terraform code to achieve this:

```hcl
resource "aws_iam_role" "firehose_role" {
  name               = "firehose-role"
  description        = "IAM role for Kinesis Firehose to access Elasticsearch"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "firehose.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ],
  })
}

resource "aws_iam_policy" "firehose_policy" {
  name        = "firehose-policy"
  description = "Policy for Kinesis Firehose to access Elasticsearch and VPC"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:CreateIndex",
          "es:PutRecord",
          "es:UpdateElasticsearchDomainConfig"
        ],
        Effect   = "Allow",
        Resource = "arn:aws:es:*:*:domain/*" # Replace with your Elasticsearch domain ARN if you prefer. Allowing all ES domains is not a best practice for production
      },
      {
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "arn:aws:logs:*:*:log-group:/aws/kinesis/*"
      },
      {
        Effect = "Allow",
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups"
        ],
        Resource = "*"
      }
    ],
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attachment" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

resource "aws_kinesis_firehose_delivery_stream" "firehose_stream" {
  name        = "my-firehose-stream"
  role_arn    = aws_iam_role.firehose_role.arn
  destination = "elasticsearch"

  elasticsearch_configuration {
    cluster_status = "ACTIVE"
    domain_arn     = "arn:aws:es:YOUR_REGION:YOUR_ACCOUNT_ID:domain/YOUR_ES_DOMAIN_NAME" # Replace with your Elasticsearch domain ARN
    index_name      = "my-index"
    index_rotation_period = "ONE_DAY"
    buffering_hints {
      interval_in_seconds = 60
      size_in_mb          = 5
    }
  }

  vpc_configuration {
    subnet_ids             = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyyyyy"] # Replace with your subnet IDs
    security_group_ids     = ["sg-zzzzzzzzzzzzzzzzz"] # Replace with your security group ID
  }

  tags = {
    Name = "MyFirehoseStream"
  }
}
```
Important considerations:

*   **Replace Placeholders:** Remember to replace `YOUR_REGION`, `YOUR_ACCOUNT_ID`, `YOUR_ES_DOMAIN_NAME`, subnet IDs, and security group ID with your actual values.
*   **Elasticsearch Domain ARN:** Providing a wildcard "*" for the Elasticsearch resource in the IAM policy is generally *not* recommended for production environments due to security implications.  Instead, specify the exact ARN of your Elasticsearch domain.
*   **VPC Configuration:** Ensure that your Elasticsearch domain is configured to be publicly accessible or that can be accessed with VPC endpoints from your specified subnets and security groups.
*   **Error Handling:** Production environments should include robust error handling, such as retry mechanisms and error logging.
*   **Scaling and Cost:** Monitor your Firehose stream's performance and adjust buffering hints and other settings according to your data volume and cost requirements.
*   **Region:** Ensure you are deploying to the correct AWS region.

