response:
Okay, let's break down the requirements for creating a Route 53 traffic policy using Terraform.

1.  **Resource:** We'll need the `aws_route53_traffic_policy` resource.
2.  **Name:** A descriptive name for the traffic policy.
3.  **Document:**  The core of the traffic policy, defining how traffic is routed. This is a JSON document.  A basic example involves a single resource with a failover configuration.
4.  **Rule:**  We will require a rule to associate the document with.
5.  **Record:** We need a record to associate the traffic policy with.

Here's a Terraform configuration that creates a Route 53 traffic policy with a simple failover rule. This setup directs traffic to a primary resource and fails over to a secondary resource if the primary becomes unavailable. Replace the placeholder domain name and resource details with your actual values.

```hcl
resource "aws_route53_traffic_policy" "example" {
  name        = "example-traffic-policy"
  description = "Traffic policy for failover between two resources"

  document = jsonencode({
    "TrafficPolicy": {
      "Id": "TP1",
      "Provider": {
        "Name": "failover",
        "Type": "weighted",
        "Weight": 100,
        "SetIdentifier": "Primary"
      },
      "ResourceGroups": [
        {
          "Id": "RG1",
          "Resources": [
            {
              "Id": "R1",
              "HealthCheckId": "hc1"
            }
          ]
        },
        {
          "Id": "RG2",
          "Resources": [
            {
              "Id": "R2",
              "HealthCheckId": "hc2"
            }
          ]
        }
      ],
      "Rules": [
        {
          "Id": "Rule1",
          "Priority": 1,
          "RuleType": "FAILOVER",
          "RRSet": "example.com",
          "ResourceGroups": ["RG1", "RG2"]
        }
      ]
    }
  })
}

resource "aws_route53_record" "example" {
  zone_id = "Z2E0XXXXXXXXXXXXX" # Replace with your Route 53 zone ID
  name    = "example.com"  # Replace with your domain
  type    = "A"
  ttl     = 300
  records = ["127.0.0.1"] # Replace with your primary IP

  traffic_policy_instance = aws_route53_traffic_policy.example.id
}


resource "aws_route53_health_check" "hc1" {
  name             = "primary-healthcheck"
  type             = "HTTP"
  request_interval = 30
  failure_threshold = 3
  enable_sni       = true

  http {
    path     = "/"
    port     = 80
    protocol = "HTTP"
  }
}

resource "aws_route53_health_check" "hc2" {
  name             = "secondary-healthcheck"
  type             = "HTTP"
  request_interval = 30
  failure_threshold = 3
  enable_sni       = true

  http {
    path     = "/"
    port     = 80
    protocol = "HTTP"
  }
}
```

extracted_code:
variable "cluster_name" {
  type        = string
  description = "The name of the EKS cluster"
  default     = "my-eks-cluster"
}

# Create an IAM role for EKS
resource "aws_iam_role" "eks_role" {
  name               = "${var.cluster_name}-eks-role"
  description        = "IAM role for EKS cluster"
  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "eks.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

# Attach EKS cluster policy to the IAM role
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  role       = aws_iam_role.eks_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
}

# Attach EKS service policy to the IAM role
resource "aws_iam_role_policy_attachment" "eks_service_policy" {
  role       = aws_iam_role.eks_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
}

# AWS EKS Cluster
resource "aws_eks_cluster" "eks" {
  name     = var.cluster_name
  role_arn = aws_iam_role.eks_role.arn

  vpc_config {
    subnet_ids = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyyyyy"] # Replace with your actual subnet IDs
  }

  # Required provisioner to configure kubectl
  provisioner "local-exec" {
    command = "aws eks --region us-east-1 update-kubeconfig --name ${self.name} --alias ${var.cluster_name}" #Replace us-east-1 with your region
    when    = create
  }

  # Provisioner to remove kubeconfig entry on destroy
  provisioner "local-exec" {
    command = "aws eks --region us-east-1 delete-kubeconfig --name ${self.name} --alias ${var.cluster_name}"  #Replace us-east-1 with your region
    when    = destroy
  }
}

output "cluster_name" {
  value = aws_eks_cluster.eks.name
}

output "kubeconfig_context" {
  value = "${var.cluster_name}"
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

variable "cluster_name" {
  type = string
  default = "test-cluster"
}

data "aws_region" "current" {}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "test_eks_1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  availability_zone = data.aws_availability_zones.available.names[0]
}

resource "aws_subnet" "test_eks_2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"

  availability_zone = data.aws_availability_zones.available.names[1]
}

resource "aws_iam_role" "example" {
  name = "${var.cluster_name}-eks"

  assume_role_policy = jsonencode({
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks.amazonaws.com"
      }
    }]
    Version = "2012-10-17"
  })
}

resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.example.name
}

resource "aws_iam_role_policy_attachment" "eks_service_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.example.name
}

resource "aws_eks_cluster" "example" {
  name     = var.cluster_name
  role_arn = aws_iam_role.example.arn

  vpc_config {
    subnet_ids = [ aws_subnet.test_eks_1.id, aws_subnet.test_eks_2.id ]
  }

  # Ensure that IAM Role permissions are created before and deleted after EKS Cluster handling.
  # Otherwise, EKS will not be able to properly delete EKS managed EC2 infrastructure such as Security Groups.
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_service_policy,
  ]

  # Manage kubectl configuration
  provisioner "local-exec" {
    command = "aws eks --region ${data.aws_region.current.name} update-kubeconfig --name ${self.name}"
  }

  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config unset users.${self.arn}"
  }
  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config unset clusters.${self.arn}"
