    security_group_ids = ["sg-zzzzzzzzzzzzzzzzz"] # Replace with your security group ID
  }

  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_vpc_resource_controller_policy
  ]

}
