response:
Okay, let's break this down into steps:

1.  **Define Variables:** We'll need a variable for the bucket suffix to allow for dynamic bucket names.
2.  **CloudGoat S3 Bucket:** Create an S3 bucket named with the base name 'cloudgoat-data' and the suffix from the variable. This bucket will have private ACLs and owner enforced.
3.  **Web Data S3 Bucket:** Create another S3 bucket with a base name 'cloudgoat-webdata' and the defined suffix.
4.  **Object Upload:** Upload 'order\_data2.csv' to the web data S3 bucket.
5.  **Public Access Block:**  Configure Public Access Block to block all public access to the web data bucket.
6.  **Bucket Policy:**  Create a bucket policy allowing `s3:PutObject` action for all principals.

Now, here's the Terraform configuration in HCL format:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

variable "bucket_suffix" {
  type        = string
  default     = "test"
  description = "Suffix to append to the bucket names"
}

resource "aws_s3_bucket" "cloudgoat_data" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
  acl    = "private"

  ownership_controls {
    enable_object_ownership = true
    rule {
      object_ownership = "BucketOwnerEnforced"
    }
  }
}

resource "aws_s3_bucket" "web_data" {
  bucket = "cloudgoat-webdata-${var.bucket_suffix}"
  acl    = "private"

  public_access_block {
    block_public_acls       = true
    ignore_public_acls       = true
    block_public_policy      = true
    restrict_public_buckets = true
  }

  bucket_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "s3:PutObject"
        Effect   = "Allow"
        Principal = "*"
        Resource = "arn:aws:s3:::${aws_s3_bucket.web_data.bucket}/*"
      }
    ]
  })
}

resource "aws_s3_object" "order_data" {
  bucket = aws_s3_bucket.web_data.bucket
  key    = "order_data2.csv"
  source = "order_data2.csv" # Ensure this file exists in the working directory
}
```

