}

resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier = "my-single-node-cluster"
  database_name      = "mydb"
  master_username    = "admin"
  master_password    = "P@sswOrd123" # PLEASE REPLACE WITH A SECURE PASSWORD

  node_type            = "dc2.small"
  number_of_nodes      = 1
  skip_final_snapshot = true

  tags = {
    Name = "My Single Node Redshift Cluster"
  }
}
