response:
Okay, let's break this down into steps to create the Terraform configuration.

1.  **IAM Role:** We need an IAM role that the Lambda function will assume. This role needs permissions to execute. We'll start with a basic execution role allowing logging to CloudWatch.
2.  **IAM Policy Document for Role Trust Relationship:**  The IAM role needs a trust relationship that allows the Lambda service to assume the role.
3.  **Lambda Function:** This is the core resource. It will need the role ARN, the function name, the runtime, the handler and the source code (defined as an archive - a zip file).
4.  **Archive File:** We'll create a local_file resource that creates a zip archive containing the lambda code. In this case, "lambda.js".

Now, let's put all this together in a Terraform configuration.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Create a ZIP archive containing the Lambda function code
resource "local_file" "lambda_archive" {
  content  = "exports.handler = async (event) => {
  console.log('Hello from Lambda!');
  return { statusCode: 200, body: 'Hello, World!' };
};"
  filename = "lambda.zip"
}

# Create an IAM role for the Lambda function
resource "aws_iam_role" "lambda_role" {
  name               = "lambda_execution_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lambda.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      }
    ]
  })
}

# Create an IAM policy for the Lambda function
resource "aws_iam_policy" "lambda_policy" {
  name        = "lambda_policy"
  description = "Policy for Lambda function"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "arn:aws:logs:*:*:*",
        Effect   = "Allow"
      }
    ]
  })
}

# Attach the IAM policy to the role
resource "aws_iam_role_policy_attachment" "lambda_role_attachment" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_policy.arn
}

# Create the Lambda function
resource "aws_lambda_function" "example" {
  function_name = "my-lambda-function"
  role          = aws_iam_role.lambda_role.arn
  runtime       = "nodejs18.x"
  handler       = "index.handler"
  source_code_bucket = ""  # Not needed when using source_code_zip_file
  source_code_zip_file = local_file.lambda_archive.filename

  timeout      = 30
  memory_size  = 128
}
