Okay, let's break this down. We need to create an EventBridge rule (formerly CloudWatch Events) that triggers an AWS Lambda function in response to an EC2 Image creation event.

Here's the plan:

1.  **Find the EC2 Image Creation Event:** We'll use the event pattern to filter for events related to the creation of EC2 images.
2.  **Specify the Target:** The target will be the Lambda function `test_lambda`.
3.  **Configure Permissions:** Ensure the EventBridge rule has permission to invoke the Lambda function. (This often needs to be handled separately via IAM policy or is assumed by the Lambda's execution role.)

```hcl
resource "aws_cloudwatch_event_rule" "ec2_image_creation_rule" {
  name        = "ec2-image-creation-trigger"
  description = "Triggers Lambda function on EC2 image creation"

  event_pattern = jsonencode({
    "source": [
      "aws.ec2"
    ],
    "detail-type": [
      "EC2 Image Created"
    ],
    "detail": {
      "event-source": ["aws.ec2"]
    }
  })

  tags = {
    Name = "ec2-image-creation-trigger"
  }
}

resource "aws_cloudwatch_event_target" "ec2_image_creation_target" {
  rule      = aws_cloudwatch_event_rule.ec2_image_creation_rule.name
  target_id = "ec2-image-lambda-trigger"
  arn       = "arn:aws:lambda:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:function:test_lambda"

  input_transformer {
    input_paths = {
      "detail" = "$.detail"
    }
    input_template = jsonencode({
      "detail": "<detail>"
    })
  }
}

data "aws_region" "current" {}
data "aws_caller_identity" "current" {}
```

