response:
Okay, let's break down the requirements to create an AWS Lambda function with Terraform.

1.  **IAM Role:** We'll need an IAM role that grants the Lambda function permissions to execute.  A basic execution role is sufficient for this example, allowing Lambda to write logs to CloudWatch.
2.  **Lambda Function:**  We'll define the Lambda function resource, specifying the function name, runtime, handler, and the IAM role. We will also upload the lambda function code "lambda.js"
3.  **Zip File:** The lambda function code "lambda.js" needs to be bundled within a `zip` file for uploading.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Replace with your desired region
}

# IAM Role for Lambda Execution
resource "aws_iam_role" "lambda_role" {
  name        = "lambda_execution_role"
  description = "IAM role for Lambda function execution"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lambda.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

# IAM Policy attachment for logging to CloudWatch
resource "aws_iam_policy" "lambda_cloudwatch_policy" {
  name        = "lambda_cloudwatch_policy"
  description = "Policy to allow Lambda to write logs to CloudWatch"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "arn:aws:logs:*:*:*"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_cloudwatch_attachment" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_cloudwatch_policy.arn
}


# Create a zip file
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_dir  = "." # Assuming lambda.js is in the current directory
  output_path = "lambda.zip"
  excludes = []
}

# Lambda Function
resource "aws_lambda_function" "example" {
  function_name = "my-lambda-function"
  role          = aws_iam_role.lambda_role.arn
  handler       = "lambda.handler" # Assuming your handler function is named 'handler' in lambda.js
  runtime       = "nodejs18.x"
  timeout       = 30

  package_type = "Zip"
  source_code_hash = data.archive_file.lambda_zip.output_sha256

  contents {
    file = data.archive_file.lambda_zip.output_path
  }
}
```

