Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.region
}

variable "table_name" {
  type    = string
  default = "my-dynamodb-table"
}

variable "regions" {
  type = list(string)
  default = ["us-east-1", "us-west-1", "us-west-2"]
}

resource "aws_dynamodb_table" "example" {
  for_each = toset(var.regions)

  name             = "${var.table_name}-${each.value}"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "id"
  attribute {
    name = "id"
    type = "S"
  }

  provider = aws.providers[each.value] # use provider aliases
}

provider "aws" {
  for_each = toset(var.regions)
  region = each.value
  alias = each.value
}
