  kafka_versions = ["2.8.1"]
  server_properties = <<EOF
auto.create.topics.enable = true
delete.topic.enable = true
default.replication.factor = 3
min.insync.replicas = 2
EOF
}


# Output MSK Cluster Information
output "msk_cluster_arn" {
  value = aws_msk_cluster.msk_cluster.arn
}

output "msk_cluster_id" {
  value = aws_msk_cluster.msk_cluster.id
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "vpc" {
    cidr_block = "192.168.0.0/22"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "subnet_az1" {
    availability_zone = data.aws_availability_zones.azs.names[0]
    cidr_block = "192.168.0.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az2" {
    availability_zone = data.aws_availability_zones.azs.names[1]
    cidr_block = "192.168.1.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az3" {
    availability_zone = data.aws_availability_zones.azs.names[2]
    cidr_block = "192.168.2.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "third" {
  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]

        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }

        security_groups = [aws_security_group.sg.id]
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = false
            }
            firehose {
                enabled = false
            }
            s3 {
                enabled = false
            }
        }
    }
}

output "zookeeper_connect_string" {
    value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
    description = "TLS connection host:port pairs"
    value = aws_msk_cluster.example.bootstrap_brokers_tls
}

response:
: Okay, let's break down the requirements and then generate the Terraform configuration for creating an MSK cluster with 3 broker nodes.

Here's the plan:

1.  **Provider Configuration:** We'll need to configure the AWS provider.  I'll assume this is already done in the user's environment, but I'll include a basic provider block for completeness.
2.  **VPC:** MSK requires a VPC. I'll create a VPC with automatically allocated subnets.
3.  **Security Groups:** MSK needs security groups for the brokers, clients, and Zookeeper.
4.  **MSK Cluster:** The core resource. We'll define the cluster with 3 broker nodes.  I'll include basic configuration like the EC2 instance type, number of brokers, and Kafka version. I'll also need a cluster name.
5.  **Outputs:**  I will output the MSK cluster information.

Here's the Terraform code:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Create a VPC
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "msk-vpc"
  }
}

# Create Subnets
resource "aws_subnet" "msk_subnet_1" {
  vpc_id     = aws_vpc.msk_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  tags = {
    Name = "msk-subnet-1"
  }
}

resource "aws_subnet" "msk_subnet_2" {
  vpc_id     = aws_vpc.msk_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired AZ
  tags = {
    Name = "msk-subnet-2"
  }
}

resource "aws_subnet" "msk_subnet_3" {
  vpc_id     = aws_vpc.msk_vpc.id
  cidr_block = "10.0.3.0/24"
  availability_zone = "us-east-1c" # Replace with your desired AZ
  tags = {
    Name = "msk-subnet-3"
  }
}


# Create Security Group for MSK Brokers
resource "aws_security_group" "msk_broker_sg" {
  name        = "msk-broker-sg"
  description = "Security group for MSK brokers"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] #Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster-example"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3
  broker_node_group {
    client_subnets = [aws_subnet.msk_subnet_1.id, aws_subnet.msk_subnet_2.id, aws_subnet.msk_subnet_3.id]
    security_groups = [aws_security_group.msk_broker_sg.id]
    instance_type   = "kafka.m5.large"
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }
  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = 1
  }
  encryption_info {
    encryption_at_rest_kms_key_id = "alias/aws/kafka"
  }
  open_monitoring {
    prometheus {
      enabled = false
    }
  }
}

resource "aws_msk_configuration" "msk_config" {
  name             = "msk-configuration-example"
  kafka_versions = ["2.8.1"]
  server_properties = <<EOF
auto.create.topics.enable = true
delete.topic.enable = true
default.replication.factor = 3
min.insync.replicas = 2
EOF
}


# Output MSK Cluster Information
output "msk_cluster_arn" {
  value = aws_msk_cluster.msk_cluster.arn
}

output "msk_cluster_id" {
  value = aws_msk_cluster.msk_cluster.id
}
```

