1.  **Resource:** We need a `confluent_msk_cluster` resource.
2.  **Cluster Name:** A unique name for the MSK cluster is required. Let's use "example-msk-cluster".
3.  **Kafka Version:**  We need to specify a Kafka version compatible with MSK. Let's use "2.8.1".
4.  **Number of Broker Nodes:** The requirement is 3 broker nodes.
5.  **Region:** The cluster must be in `us-east-2`.
6.  **Broker Node Group ID:** A unique ID for the broker node group. We'll call it "broker-node-group-1".
7. **Instance Type:** We'll use "kafka.m5.large" for the brokers.
8. **Client Authentication:** We will use TLS for client authentication.
9. **Encryption:** We’ll use encryption at rest with AWS managed keys.

Here’s the Terraform configuration:

```hcl
terraform {
  required_providers {
    confluent = {
      source  = "confluent-cloud/confluent"
      version = "~> 2.0"
    }
  }
}

provider "confluent" {
  confluent_api_key = var.confluent_api_key
  confluent_api_secret = var.confluent_api_secret
}

resource "confluent_msk_cluster" "example" {
  name             = "example-msk-cluster"
  kafka_version    = "2.8.1"
  region           = "us-east-2"

  broker_node_group {
    id           = "broker-node-group-1"
    broker_az_list = ["us-east-2a", "us-east-2b", "us-east-2c"]
    client_groups = []
    instance_type = "kafka.m5.large"
    node_count    = 3
    security_groups = []
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = "" # Use AWS managed KMS Key
  }

  scaling_policy {
    auto_scaling {
      max_brokers = 3
      min_brokers = 3
    }
  }

  monitoring {
    exclude_list = []
  }

  tls {
    certificate_authority_arns = []
  }
}

variable "confluent_api_key" {
  type = string
  description = "The Confluent API key"
  sensitive = true
}
variable "confluent_api_secret" {
  type = string
  description = "The Confluent API secret"
  sensitive = true
}
