    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. VPC and Subnets (Assuming they exist - replace with your actual IDs)
variable "vpc_id" {
  type = string
  description = "The ID of the VPC"
  default = "vpc-xxxxxxxxxxxxxxxxx"
}

variable "subnet_ids" {
  type = list(string)
  description = "A list of subnet IDs"
  default = ["subnet-xxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyy"]
}

# 2. MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group {
    client_subnets = var.subnet_ids
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 100
  }

  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = 1
  }

  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:us-east-1:123456789012:key/your-kms-key-id" # Replace with a KMS key id
  }

  open_to_public_ca_certificates = false
  vpc_config {
    subnet_ids = var.subnet_ids
    security_groups = [aws_security_group.msk_sg.id]
  }
}

# MSK Configuration for Firehose Integration
resource "aws_msk_configuration" "msk_config" {
  name             = "my-msk-config"
  kafka_versions = ["2.8.1"]

  server_properties = <<EOT
auto.create.topics.enable = true
log.dirs = /var/log/kafka/
zookeeper.connect = ${aws_msk_cluster.msk_cluster.zookeeper_connect_string}
EOT
}

# 3. Kinesis Firehose
resource "aws_kinesis_firehose_delivery_stream" "firehose_stream" {
  name        = "msk-logs-firehose"
  destination = "s3"

  s3_configuration {
    role_arn           = "arn:aws:iam::123456789012:role/KinesisFirehoseRole" # Replace with your Firehose Role ARN
    bucket_name        = "your-s3-bucket-name" # Replace with your S3 Bucket name
    prefix             = "msk-logs"
    compression_format = "GZIP"
  }
}

# 4. Security Group
resource "aws_security_group" "msk_sg" {
  name        = "msk-sg"
  description = "Security group for MSK cluster"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # can restrict this
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # can restrict this
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Output the MSK cluster information
output "msk_cluster_arn" {
  value = aws_msk_cluster.msk_cluster.arn
}

output "firehose_stream_arn" {
  value = aws_kinesis_firehose_delivery_stream.firehose_stream.arn
