reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "vpc" {
    cidr_block = "192.168.0.0/22"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "subnet_az1" {
    availability_zone = data.aws_availability_zones.azs.names[0]
    cidr_block = "192.168.0.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az2" {
    availability_zone = data.aws_availability_zones.azs.names[1]
    cidr_block = "192.168.1.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az3" {
    availability_zone = data.aws_availability_zones.azs.names[2]
    cidr_block = "192.168.2.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "third" {
  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_s3_bucket" "bucket" {
    bucket_prefix = "msk-broker-logs-bucket-"
}

resource "aws_s3_bucket_ownership_controls" "example" {
    bucket = aws_s3_bucket.bucket.id
    rule {
        object_ownership = "BucketOwnerPreferred"
    }
}

resource "aws_s3_bucket_acl" "example" {
    depends_on = [aws_s3_bucket_ownership_controls.example]

    bucket = aws_s3_bucket.bucket.id
    acl = "private"
}

data "aws_iam_policy_document" "assume_role" {
    statement {
        effect = "Allow"
        principals {
            type = "Service"
            identifiers = ["firehose.amazonaws.com"]
        }
        actions = ["sts:AssumeRole"]
    }
}

resource "aws_iam_role" "firehose_role" {
    name = "firehose_test_role"
    assume_role_policy = data.aws_iam_policy_document.assume_role.json
}

resource "aws_kinesis_firehose_delivery_stream" "test_stream" {
    name = "terraform-kinesis-firehose-msk-broker-logs-stream"
    destination = "extended_s3"

    extended_s3_configuration {
        role_arn = aws_iam_role.firehose_role.arn
        bucket_arn = aws_s3_bucket.bucket.arn
    }

    tags = {
        LogDeliveryEnabled = "placeholder"
    }

    lifecycle {
        ignore_changes = [
            tags["LogDeliveryEnabled"],
        ]
    }
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]
        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }
        security_groups = [aws_security_group.sg.id]
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = false
            }
            firehose {
                enabled         = true
                delivery_stream = aws_kinesis_firehose_delivery_stream.test_stream.name
            }
            s3 {
                enabled = true
                bucket  = aws_s3_bucket.bucket.id
                prefix  = "logs/msk-"
            }
        }
    }
}

output "zookeeper_connect_string" {
    value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
    description = "TLS connection host:port pairs"
    value = aws_msk_cluster.example.bootstrap_brokers_tls
}

response:
Okay, let's break down the requirements and then build the Terraform configuration.

1.  **MSK Cluster:** We need to define an MSK cluster resource. This requires specifying a cluster name, Kafka version, number of broker nodes, and broker node group information including instance type and EBS volume size.  We'll also need to define VPC configuration, subnet IDs, and security groups.
2.  **Kinesis Firehose:** We need to create a Kinesis Firehose delivery stream. This will act as the destination for our MSK cluster logs. We'll define the stream name and configure the destination (S3 in this example).
3.  **MSK Configuration:** We need to associate the MSK cluster with Kinesis Firehose for logging. This generally involves configuration within the MSK cluster settings to push logs to the Firehose stream's ARN.
4.  **Networking:** We'll assume an existing VPC and subnets. IP addressing will be auto-assigned via Terraform. We'll create security group rules for MSK brokers to communicate with the Firehose.
5.  **IAM Roles:** MSK requires an IAM role for service access, and Kinesis Firehose also requires permissions. Terraform will take care of these roles.

Here's the Terraform configuration to accomplish this. Note that the example uses a basic S3 destination for Firehose. More complex destinations like Redshift or Elasticsearch can be added as needed.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. VPC and Subnets (Assuming they exist - replace with your actual IDs)
variable "vpc_id" {
  type = string
  description = "The ID of the VPC"
  default = "vpc-xxxxxxxxxxxxxxxxx"
}

variable "subnet_ids" {
  type = list(string)
  description = "A list of subnet IDs"
  default = ["subnet-xxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyy"]
}

# 2. MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group {
    client_subnets = var.subnet_ids
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 100
  }

  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = 1
  }

  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:us-east-1:123456789012:key/your-kms-key-id" # Replace with a KMS key id
  }

  open_to_public_ca_certificates = false
  vpc_config {
    subnet_ids = var.subnet_ids
    security_groups = [aws_security_group.msk_sg.id]
  }
}

# MSK Configuration for Firehose Integration
resource "aws_msk_configuration" "msk_config" {
  name             = "my-msk-config"
  kafka_versions = ["2.8.1"]

  server_properties = <<EOT
auto.create.topics.enable = true
log.dirs = /var/log/kafka/
zookeeper.connect = ${aws_msk_cluster.msk_cluster.zookeeper_connect_string}
EOT
}

# 3. Kinesis Firehose
resource "aws_kinesis_firehose_delivery_stream" "firehose_stream" {
  name        = "msk-logs-firehose"
  destination = "s3"

  s3_configuration {
    role_arn           = "arn:aws:iam::123456789012:role/KinesisFirehoseRole" # Replace with your Firehose Role ARN
    bucket_name        = "your-s3-bucket-name" # Replace with your S3 Bucket name
    prefix             = "msk-logs"
    compression_format = "GZIP"
  }
}

# 4. Security Group
resource "aws_security_group" "msk_sg" {
  name        = "msk-sg"
  description = "Security group for MSK cluster"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # can restrict this
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # can restrict this
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Output the MSK cluster information
output "msk_cluster_arn" {
  value = aws_msk_cluster.msk_cluster.arn
}

output "firehose_stream_arn" {
  value = aws_kinesis_firehose_delivery_stream.firehose_stream.arn
}
```

