terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "vpc" {
    cidr_block = "192.168.0.0/22"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "subnet_az1" {
    availability_zone = data.aws_availability_zones.azs.names[0]
    cidr_block = "192.168.0.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az2" {
    availability_zone = data.aws_availability_zones.azs.names[1]
    cidr_block = "192.168.1.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az3" {
    availability_zone = data.aws_availability_zones.azs.names[2]
    cidr_block = "192.168.2.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "third" {
  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

data "aws_iam_policy_document" "assume_role" {
    statement {
        effect = "Allow"
        principals {
            type = "Service"
            identifiers = ["firehose.amazonaws.com"]
        }
        actions = ["sts:AssumeRole"]
        }
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]
        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }
        security_groups = [aws_security_group.sg.id]
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = false
            }
            firehose {
                enabled = false
            }
            s3 {
                enabled = false
            }
        }
    }
}

output "zookeeper_connect_string" {
    value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
description = "TLS connection host:port pairs"
    value = aws_msk_cluster.example.bootstrap_brokers_tls
}

response:
:
Okay, let's break down the requirements to create a Terraform configuration for a managed MSK cluster with JMX Exporter and Node Exporter enabled.

1.  **MSK Cluster:** We'll need to define an `aws_msk_cluster` resource. This involves defining cluster name, Kafka and ZooKeeper versions, number of broker nodes, and the VPC configuration.
2.  **VPC Configuration:**  MSK requires a VPC with specific configurations.  We'll need to ensure sufficient subnets (at least 3) are available in multiple Availability Zones.  We'll create these within the Terraform configuration if they don't exist.
3.  **Security Groups:**  MSK requires security groups to control access to the cluster. We'll create security groups for brokers and clients.
4.  **JMX Exporter:** Enable JMX monitoring on the MSK brokers. We need to set the `enhanced_monitoring` to `true` to enable JMX monitoring.
5.  **Node Exporter:** Enable node monitoring on the MSK brokers. We need to set the `node_exporter` to `true`.
6.  **IAM Roles:** MSK requires AWS IAM roles to access other AWS resources. Terraform will manage the creation of these roles.
7. **Cluster Configuration:** Configure the MSK cluster with the appropriate settings for Broker node group, configuration info.
8. **Encryption:** Configure encryption at rest and in transit.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2" # Replace with your desired region
}

# VPC and Subnets (Create if they don't exist)
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet_1" {
  vpc_id     = aws_vpc.msk_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-west-2a" # Replace with your desired AZ
  tags = {
    Name = "msk-subnet-1"
  }
}

resource "aws_subnet" "msk_subnet_2" {
  vpc_id     = aws_vpc.msk_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-west-2b" # Replace with your desired AZ
  tags = {
    Name = "msk-subnet-2"
  }
}

resource "aws_subnet" "msk_subnet_3" {
  vpc_id     = aws_vpc.msk_vpc.id
  cidr_block = "10.0.3.0/24"
  availability_zone = "us-west-2c" # Replace with your desired AZ
  tags = {
    Name = "msk-subnet-3"
  }
}

# Security Groups
resource "aws_security_group" "msk_broker_sg" {
  name        = "msk-broker-sg"
  description = "Security group for MSK brokers"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] #Consider restricting this to your known IPs/Networks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "msk_client_sg" {
  name        = "msk-client-sg"
  description = "Security group for MSK clients"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] #Consider restricting this to your known IPs/Networks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3
  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:us-west-2:123456789012:key/your-kms-key-id" #Replace with your KMS key ARN
  }

  configuration_info {
    arn      = "arn:aws:kafka:us-west-2:123456789012:configuration/my-msk-config" # Replace with your configuration ARN
    revision = 1
  }
  open_to_public_ca_certificates = false
  broker_node_group_info {
    client_subnets = [aws_subnet.msk_subnet_1.id, aws_subnet.msk_subnet_2.id, aws_subnet.msk_subnet_3.id]
    security_groups = [aws_security_group.msk_broker_sg.id]
  }

  enhanced_monitoring {
    jmx_exporter {
      enabled = true
    }
    node_exporter {
      enabled = true
    }
  }
  tags = {
    Name = "my-msk-cluster"
  }
}
