: Okay, let's break down the requirements to create a serverless MSK cluster in `us-east2`.

1.  **Provider Configuration:** We'll need to configure the AWS provider, specifying the region as `us-east2`.
2.  **MSK Cluster Resource:** We'll define an `aws_msk_cluster` resource to create the MSK cluster. We'll use the 'serverless' option.
3.  **Configuration Information:** Specify the cluster name, kafka version, and number of kafka brokers.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east2"
}

resource "aws_msk_cluster" "serverless_msk" {
  cluster_name           = "serverless-msk-cluster"
  kafka_version           = "3.2"
  number_of_broker_nodes = 3 # Minimum value of one for serverless clusters

  configuration_info {
    arn      = "arn:aws:kafka:us-east2::configuration/serverless-msk-config"
    revision = 1
  }

  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:us-east2:111122223333:key/your-kms-key-id" # Replace with your KMS key ID
  }

  open_monitoring {
    prometheus {
      enabled = true
    }
  }

  tags = {
    Name        = "Serverless MSK Cluster"
    Environment = "Development"
  }

  client_authentication {
    tls {
      certificate_authority_arns = []

    }
  }
}
