response:
Okay, let's break down this request and build the Terraform configuration for an Amazon MSK cluster with the specified requirements.

1.  **MSK Cluster:** We need to define an `aws_msk_cluster` resource.  This will include settings for the number of brokers (3), broker node group specifications (instance type, client subnets, security groups), and encryption at rest.
2.  **Encryption at Rest:** This will be implemented via KMS key integration into the MSK cluster resource.
3.  **Open Monitoring:** This requires enabling enhanced monitoring and specifying the CloudWatch log group.
4.  **CloudWatch Log Group:** We need an `aws_cloudwatch_log_group` resource to store MSK broker logs.
5.  **S3 Bucket:** An `aws_s3_bucket` resource for the output destination. I will make sure the bucket is versioned.
6.  **Kinesis Firehose Delivery Stream:** We will use `aws_kinesis_firehose_delivery_stream` resource. This will be configured to receive data from MSK, transform it if necessary, and deliver it to S3.
7.  **IAM Roles and Policies:** MSK needs permissions to write to CloudWatch Logs and Kinesis Firehose needs permissions to write to S3. We'll define corresponding IAM Roles.

Here's the Terraform configuration:

```hcl
resource "aws_kms_key" "msk_key" {
  description = "KMS key for MSK encryption"
  tags = {
    name = "msk-encryption-key"
  }
}

resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "msk-cluster-logs"
  retention_in_days = 14
  tags = {
    Name = "MSK Cluster Logs"
  }
}

resource "aws_s3_bucket" "msk_s3_bucket" {
  bucket = "msk-cluster-output"
  versioning {
    enabled = true
  }
  tags = {
    Name        = "MSK Cluster S3 Bucket"
  }
}

resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3
  encryption_info {
    encryption_at_rest_kms_key_id = aws_kms_key.msk_key.arn
  }
  broker_node_group_info {
    client_subnets = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyyyyy", "subnet-zzzzzzzzzzzzzzzzz"] # Replace with your subnet IDs
    instance_type   = "kafka.m5.large"
    security_groups = ["sg-xxxxxxxxxxxxxxxxx"] # Replace with your security group ID
  }
  configuration_info {
    arn      = "arn:aws:kafka:us-east-1:123456789012:config/current" # Replace with your config ARN
    revision = 1
  }
  open_monitoring {
     enhanced_monitoring {
        type = "DEFAULT"
     }
    prometheus {
      arn = "arn:aws:prometheus:us-east-1:123456789012:exporter/MSKClusterExporter"    # Replace with your Prometheus ARN
      port = 9094
    }
  }
  logging_info {
    broker_logs {
      cloudwatch_logs {
        log_group_name = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
  }
}

resource "aws_iam_role" "msk_firehose_role" {
  name = "msk-firehose-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "firehose.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ]
  })
}

resource "aws_iam_policy" "msk_firehose_policy" {
  name        = "msk-firehose-policy"
  description = "Policy for Firehose to write to S3"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = ["s3:PutObject", "s3:GetBucketAcl", "s3:GetObjectAcl"],
        Effect   = "Allow",
        Resource = [
          aws_s3_bucket.msk_s3_bucket.arn,
          "${aws_s3_bucket.msk_s3_bucket.arn}/*",
        ],
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_firehose_attachment" {
  role       = aws_iam_role.msk_firehose_role.name
  policy_arn = aws_iam_policy.msk_firehose_policy.arn
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose-stream"
  destination = "s3"
  s3_configuration {
    role_arn    = aws_iam_role.msk_firehose_role.arn
    bucket_name = aws_s3_bucket.msk_s3_bucket.bucket_name
    prefix      = "msk-output/"
  }
  depends_on = [aws_iam_role_policy_attachment.msk_firehose_attachment]
}
```

