terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "vpc" {
    cidr_block = "192.168.0.0/22"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "subnet_az1" {
    availability_zone = data.aws_availability_zones.azs.names[0]
    cidr_block = "192.168.0.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az2" {
    availability_zone = data.aws_availability_zones.azs.names[1]
    cidr_block = "192.168.1.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az3" {
    availability_zone = data.aws_availability_zones.azs.names[2]
    cidr_block = "192.168.2.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "third" {
  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]
        storage_info {
            ebs_storage_info {
                volume_size = 100
            }
        }
        security_groups = [aws_security_group.sg.id]
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = false
            }
            firehose {
                enabled = false
            }
            s3 {
                enabled = false
            }
        }
    }
}

resource "aws_s3_bucket" "example" {
    bucket_prefix = "my-bucket-"
}

resource "aws_s3_object" "example" {
    bucket = aws_s3_bucket.example.id
    key = "my-connector.zip"
    source = "./supplement/my-connector.zip"
}

resource "aws_mskconnect_custom_plugin" "example" {
    name = "my-connector"
    content_type = "ZIP"
    location {
        s3 {
            bucket_arn = aws_s3_bucket.example.arn
            file_key = aws_s3_object.example.key
        }
    }
}

resource "aws_iam_role" "aws_msk_connector_role" {
    name = "test_role"

    assume_role_policy = jsonencode({
        Version = "2012-10-17"
        Statement = [
            {
                Effect = "Allow",
                Principal = {
                    Service = "kafkaconnect.amazonaws.com"
                },
                Action = "sts:AssumeRole",
            }
        ]
    })
}

resource "aws_iam_policy" "msk_connector_policy" {
  name        = "msk-connector-policy"
  description = "IAM policy for MSK Connector"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kafka:DescribeCluster",
          "kafka:DescribeClusterV2",
          "kafka:DescribeTopic",
          "kafka:CreateTopic",
          "kafka:DeleteTopic",
          "kafka:WriteData",
          "kafka:ReadData"
        ]
        Resource = "${aws_msk_cluster.example.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          "${aws_s3_bucket.example.arn}",
          "${aws_s3_bucket.example.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connector_attach_policy" {
  role       = aws_iam_role.aws_msk_connector_role.name
  policy_arn = aws_iam_policy.msk_connector_policy.arn
}


resource "aws_mskconnect_connector" "example_connector" {
    name = "example"

    kafkaconnect_version = "2.7.1"

    capacity {
        autoscaling {
            mcu_count = 1
            min_worker_count = 1
            max_worker_count = 2

            scale_in_policy {
                cpu_utilization_percentage = 20
            }

            scale_out_policy {
                cpu_utilization_percentage = 80
            }
        }
    }

    connector_configuration = {
        # modify the following connector class according to your code
        # the connector code depends on your msk setting
        # we will not provide an example connector code here
        "connector.class" = "com.github.xxx.kafka.connect.simulator.SimulatorSinkConnector"
        "tasks.max" = "1"
        "topics" = "example"
    }

    kafka_cluster {
        apache_kafka_cluster {
            bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_tls

            vpc {
                security_groups = [aws_security_group.sg.id]
                subnets = [aws_subnet.subnet_az1.id, 
                           aws_subnet.subnet_az2.id, 
                           aws_subnet.subnet_az3.id]
            }
        }
    }

    kafka_cluster_client_authentication {
        authentication_type = "NONE"
    }

    kafka_cluster_encryption_in_transit {
        encryption_type = "PLAINTEXT"
    }

    plugin {
        custom_plugin {
            arn = aws_mskconnect_custom_plugin.example.arn
            revision = aws_mskconnect_custom_plugin.example.latest_revision
        }
    }

    service_execution_role_arn = aws_iam_role.aws_msk_connector_role.arn
}

response:
Okay, let's break this down into steps to build the Terraform configuration.

1.  **MSK Cluster:** We need to define an MSK cluster with 3 broker nodes in `us-east-1`. This will require specifying the Kafka and ZooKeeper versions, instance types, and number of brokers.
2.  **MSK Connect:** Next, we'll create an MSK Connect cluster. We need to decide on the instance type and the number of worker nodes.
3.  **MSK Connect Custom Plugin:** We'll upload the custom plugin `debezium.zip` to S3 and then register it with MSK Connect using the S3 location.
4.  **MSK Connect Connector:** Finally we create the connector that utilises the custom plugin.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# MSK Cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "example-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3
  broker_node_group {
    client_subnets = [
      "subnet-xxxxxxxxxxxxxxxxx", # Replace with your subnet IDs
      "subnet-xxxxxxxxxxxxxxxxx", # Replace with your subnet IDs
      "subnet-xxxxxxxxxxxxxxxxx"  # Replace with your subnet IDs
    ]
    security_groups = [
      "sg-xxxxxxxxxxxxxxxxx" # Replace with your Security Group ID
    ]
    instance_type = "kafka.m5.large"
  }

  configuration_info {
    arn      = "arn:aws:kafka:us-east-1:xxxxxxxxxxxx:configuration/example-config" # Replace with your configuration ARN if you have a custom one
    revision = 1
  }

  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:us-east-1:xxxxxxxxxxxx:key/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx" # Replace with your KMS key ARN
  }

  open_to_public_ca_certificates = false
}

# MSK Connect Cluster
resource "aws_msk_connect_cluster" "example" {
  cluster_name       = "example-msk-connect-cluster"
  min_worker_count   = 2
  max_worker_count   = 4
  worker_config {
    no_delimiter = false
  }

  vpc_subnet_ids = [
    "subnet-xxxxxxxxxxxxxxxxx", # Replace with your subnet IDs
    "subnet-xxxxxxxxxxxxxxxxx"  # Replace with your subnet IDs
  ]
  security_group_ids = [
    "sg-xxxxxxxxxxxxxxxxx" # Replace with your Security Group ID
  ]
}

# Upload Custom Plugin to S3 (replace with your S3 bucket details)
resource "aws_s3_bucket_object" "debezium_plugin" {
  bucket = "your-s3-bucket-name" # Replace with your S3 bucket name
  key    = "debezium.zip"
  source = "debezium.zip" # Local path to your debezium plugin
}

# MSK Connect Custom Plugin
resource "aws_msk_connect_custom_plugin" "debezium" {
  name        = "debezium"
  location {
    s3 {
      bucket  = "your-s3-bucket-name" # Replace with your S3 bucket name
      object  = "debezium.zip"
    }
  }
}

# MSK Connect Connector
resource "aws_msk_connect_connector" "debezium_connector" {
  name         = "debezium-connector"
  cluster_name = aws_msk_connect_cluster.example.cluster_name
  connector_configuration {
    properties = {
      "tasks.max" = "1"
      "topics" = "your-topic-name" # Replace with topic name
      "plugin.class" = "io.debezium.connector.mysql.MySqlConnector"
      # Add other connector properties...
    }
  }
  capacity {
    auto_scaling {
      max_capacity = 4
      min_capacity = 1
    }
  }
}
