    lifecycle {
        ignore_changes = [
            tags["LogDeliveryEnabled"],
        ]
    }
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]
        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }
        security_groups = [aws_security_group.sg.id]
    }

    encryption_info {
        encryption_at_rest_kms_key_arn = aws_kms_key.kms.arn
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = true
                log_group = aws_cloudwatch_log_group.test.name
            }
            firehose {
                enabled = true
                delivery_stream = aws_kinesis_firehose_delivery_stream.test_stream.name
            }
            s3 {
                enabled = true
                bucket = aws_s3_bucket.log_bucket.id
                prefix = "logs/msk-"
            }
        }
    }
}

resource "aws_s3_bucket" "example" {
    bucket_prefix = "my-bucket-"
}

resource "aws_s3_object" "example" {
    bucket = aws_s3_bucket.example.id
    key = "my-connector.zip"
    source = "./supplement/my-connector.zip"
}

resource "aws_mskconnect_custom_plugin" "example" {
    name = "my-connector"
    content_type = "ZIP"
    location {
        s3 {
            bucket_arn = aws_s3_bucket.example.arn
            file_key = aws_s3_object.example.key
        }
    }
}

resource "aws_iam_role" "aws_msk_connector_role" {
    name = "test_role"

    assume_role_policy = jsonencode({
        Version = "2012-10-17"
        Statement = [
            {
                Effect = "Allow",
                Principal = {
                    Service = "kafkaconnect.amazonaws.com"
                },
                Action = "sts:AssumeRole",
            }
        ]
    })
}

resource "aws_iam_policy" "msk_connector_policy" {
  name        = "msk-connector-policy"
  description = "IAM policy for MSK Connector"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kafka:DescribeCluster",
          "kafka:DescribeClusterV2",
          "kafka:DescribeTopic",
          "kafka:CreateTopic",
          "kafka:DeleteTopic",
          "kafka:WriteData",
          "kafka:ReadData"
        ]
        Resource = "${aws_msk_cluster.example.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          "${aws_s3_bucket.example.arn}",
          "${aws_s3_bucket.example.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connector_attach_policy" {
  role       = aws_iam_role.aws_msk_connector_role.name
  policy_arn = aws_iam_policy.msk_connector_policy.arn
}


resource "aws_mskconnect_connector" "example_connector" {
    name = "example"

    kafkaconnect_version = "2.7.1"

    capacity {
        autoscaling {
            mcu_count = 1
            min_worker_count = 1
            max_worker_count = 2

            scale_in_policy {
                cpu_utilization_percentage = 20
            }

            scale_out_policy {
                cpu_utilization_percentage = 80
            }
        }
    }

    connector_configuration = {
        # modify the following connector class according to your code
        # the connector code depends on your msk setting
        # we will not provide an example connector code here
        "connector.class" = "com.github.xxx.kafka.connect.simulator.SimulatorSinkConnector"
        "tasks.max" = "1"
        "topics" = "example"
    }

    kafka_cluster {
        apache_kafka_cluster {
            bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_tls

            vpc {
                security_groups = [aws_security_group.sg.id]
                subnets = [aws_subnet.subnet_az1.id, 
                           aws_subnet.subnet_az2.id, 
                           aws_subnet.subnet_az3.id]
            }
        }
    }

    kafka_cluster_client_authentication {
        authentication_type = "NONE"
    }

    kafka_cluster_encryption_in_transit {
        encryption_type = "PLAINTEXT"
    }

    plugin {
        custom_plugin {
            arn = aws_mskconnect_custom_plugin.example.arn
            revision = aws_mskconnect_custom_plugin.example.latest_revision
        }
    }

    service_execution_role_arn = aws_iam_role.aws_msk_connector_role.arn
}

response:
Okay, let's break down this request into manageable Terraform components. We need to create:

1.  **MSK Cluster:** With 3 brokers, encryption at rest, and open monitoring enabled.
2.  **CloudWatch Log Group:** For MSK cluster logs.
3.  **S3 Bucket:** For MSK configuration backups and potentially other data.
4.  **Kinesis Firehose Delivery Stream:** To ingest MSK data.
5.  **MSK Connect Custom Plugin:** Upload a custom plugin ("debezium.zip").
6.  **MSK Connect Connector:**  Configured to use the uploaded custom plugin and connect to the MSK cluster.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2" # Replace with your desired region
}

# 1. S3 Bucket
resource "aws_s3_bucket" "msk_bucket" {
  bucket = "msk-terraform-bucket-unique" # Replace with a unique bucket name
  acl    = "private"
  versioning {
    enabled = true
  }

  tags = {
    Name        = "MSK Bucket"
    Environment = "Dev"
  }
}

# 2. CloudWatch Log Group
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "msk-cluster-logs"
  retention_in_days = 7

  tags = {
    Name        = "MSK Log Group"
    Environment = "Dev"
  }
}

# 3. MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster-unique" # Replace with a unique cluster name
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3
  broker_node_group {
    client_subnets = [
      "subnet-xxxxxxxxxxxxxxxxx", # Replace with your subnet IDs
      "subnet-xxxxxxxxxxxxxxxxx",
      "subnet-xxxxxxxxxxxxxxxxx"
    ]
    instance_type = "kafka.m5.large"
  }
  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:us-west-2:xxxxxxxxxxxx:key/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx" # Replace with your KMS key ARN
  }
  open_monitoring {
    prometheus {
      jmx_exporter {
        export_jmx_metrics = true
      }
    }
  }
  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = 1
  }
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled = true
        log_group_name = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
  }
}

resource "aws_msk_configuration" "msk_config" {
  name             = "msk-config"
  kafka_versions   = ["2.8.1"]
  server_properties = <<EOF
auto.create.topics.enable = true
delete.topic.enable = true
default.replication.factor = 2
min.insync.replicas = 1
log.retention.hours = 168
log.retention.bytes = -1
EOF
}

# 4. Kinesis Firehose Delivery Stream (Basic configuration - adapt to your needs)
resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose"
  destination = "s3"
  s3_configuration {
    bucket = aws_s3_bucket.msk_bucket.bucket
    prefix = "msk-data/"
    role_arn = "arn:aws:iam::xxxxxxxxxxxx:role/KinesisFirehoseRole"  # Replace with your Firehose IAM Role ARN
  }
  tags = {
    Name        = "MSK Firehose"
    Environment = "Dev"
  }
}

# 5. MSK Connect Custom Plugin
resource "aws_msk_connect_custom_plugin" "debezium_plugin" {
  name        = "debezium-plugin"
  location {
    s3 {
      bucket = aws_s3_bucket.msk_bucket.bucket
      key    = "debezium.zip"
    }
  }
}

# 6. MSK Connect Connector
resource "aws_msk_connect_connector" "debezium_connector" {
  name           = "debezium-connector"
  capacity {
    auto_scaling {
      max_capacity = 1
      min_capacity = 1
    }
  }
  connector_configuration {
    properties = {
      "tasks.max" = "1"
      "connector.class" = "io.debezium.connector.jdbc.JdbcSourceConnector"

      "database.hostname"   = "your_database_host"
      "database.port"       = "5432"
      "database.user"       = "your_database_user"
      "database.password"   = "your_database_password"
      "database.server.name" = "your_database_server_name"
      "database.include.list" = "public"
    }
  }

  kms_key_id = "arn:aws:kms:us-west-2:xxxxxxxxxxxx:key/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx" # Replace with your KMS key ARN
  log_delivery_role_arn = "arn:aws:iam::xxxxxxxxxxxx:role/MSKConnectLogDeliveryRole" # Replace with your MSK Connect Log Delivery Role ARN
  service_arn = aws_msk_cluster.msk_cluster.arn
  plugin_arn = aws_msk_connect_custom_plugin.debezium_plugin.arn
}
```

Important considerations:

*   **Replace Placeholders:** Update all placeholders (e.g., subnet IDs, KMS key ARNs, IAM role ARNs, unique names, database credentials) with your actual values.
*   **IAM Permissions:**  Ensure the IAM roles used for MSK Connect, Kinesis Firehose, and KMS have the necessary permissions.
*   **Networking:** Configure security groups and network ACLs to allow traffic between MSK, Kinesis Firehose, and other relevant services.
*   **Custom Plugin:** You'll need to upload the `debezium.zip` file to your S3 bucket beforehand.
*   **Database Configuration:**  Adapt the `connector_configuration` to match your specific database setup.  The example is for a PostgreSQL database, adjust as needed for MySQL, Oracle, etc.
*   **Region:** Configure the AWS region in the provider block.
*   **Error Handling:** Add appropriate error handling and validation to the Terraform configuration.
*   **KMS Keys:**  Ensure KMS keys are configured correctly for encryption both at rest and for MSK Connect.

This provides a complete starting point.  You may need to further customize it based on your specific requirements. Remember to `terraform init`, `terraform plan`, and `terraform apply` to deploy the infrastructure.

