response:
Okay, let's break down the Terraform configuration for an AWS Neptune cluster with custom parameter groups.

1.  **Neptune Cluster:** We'll define a `aws_neptune_cluster` resource. This will be the core of our setup, specifying the engine version, instance class, and other crucial parameters.

2.  **Cluster Parameter Group:** We'll create a `aws_neptune_cluster_parameter_group` resource. We'll need to define the name, family, and parameters of this group before associating it with the cluster.

3.  **Instance:** We’ll define a `aws_neptune_instance` resource, tied to the Neptune cluster.

4.  **Instance Parameter Group:** We'll create an `aws_neptune_instance_parameter_group` resource and associate it with our Neptune instance. Similar to the cluster parameter group, we'll define the name, family, and parameters.

5.  **Security Group:** A security group will be needed, allowing inbound traffic on the Neptune port (8182 by default).

Here's the Terraform configuration:

```hcl
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-sg"
  description = "Allow inbound traffic to Neptune cluster"

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: Restrict this in production!
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_neptune_cluster_parameter_group" "cluster_param_group" {
  name   = "neptune-cluster-param-group"
  family = "neptune-db"

  parameter {
    name  = "max_connections"
    value = "200"
  }
}

resource "aws_neptune_instance_parameter_group" "instance_param_group" {
  name   = "neptune-instance-param-group"
  family = "neptune-db"

  parameter {
    name  = "transaction_isolation"
    value = "READ_COMMITTED"
  }
}


resource "aws_neptune_cluster" "default" {
  cluster_identifier      = "neptune-cluster"
  engine                 = "neptune"
  engine_version         = "1.0"
  instance_class         = "neptune-db.r5.large"
  vpc_security_group_ids = [aws_security_group.neptune_sg.id]
  skip_cluster_parameter_group = false
  cluster_parameter_group_name = aws_neptune_cluster_parameter_group.cluster_param_group.name

  tags = {
    Name = "Neptune Cluster"
  }
}

resource "aws_neptune_instance" "default" {
  cluster_identifier = aws_neptune_cluster.default.cluster_identifier
  instance_class     = "neptune-db.r5.large"
  engine             = "neptune"
  instance_parameter_group_name = aws_neptune_instance_parameter_group.instance_param_group.name
  tags = {
    Name = "Neptune Instance"
  }
}
```

