response:
Okay, let's break down the creation of an AWS Redshift cluster with endpoint access from two subnets using Terraform. Here's the plan:

1.  **Provider Configuration:** We'll start by ensuring the AWS provider is correctly configured (region, etc.).  This part is assumed to be pre-configured in most use cases, so it will be kept minimal.
2.  **VPC and Subnets:**  We'll need a VPC and at least two subnets within that VPC to allow endpoint access.  For simplicity, I'll define the subnets directly. In a real-world scenario, you'd likely reference existing subnets.
3.  **Redshift Cluster Definition:**  We'll define the `aws_redshift_cluster` resource. This will include settings like cluster identifier, database name, node type, number of nodes, master username, and password. Most importantly, we will configure the `cluster_subnet_group_name` to associate the cluster with our defined subnets.
4.  **Security Group:** Create a security group to allow inbound traffic from the subnets to the Redshift cluster.

Here’s the Terraform configuration to implement these steps:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Define Subnets
resource "aws_subnet" "subnet_1" {
  vpc_id            = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Create Redshift Subnet Group
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "my-redshift-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]
}

# Create Security Group
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound traffic from subnets"
  vpc_id      = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet_1.cidr_block, aws_subnet.subnet_2.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create Redshift Cluster
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier  = "my-redshift-cluster"
  database_name       = "mydb"
  master_username     = "admin"
  master_password     = "P@sswOrd123" # Replace with a strong password
  node_type           = "dc2.large"
  number_of_nodes     = 2
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
  skip_final_snapshot = true #Remove it for production
}
```

