response:
Okay, let's break down the Terraform configuration needed for an autograder system using AWS S3 and CodeBuild.

1.  **S3 Bucket:**  We'll need an S3 bucket to store the student submissions (code), and potentially the results of the autograding. We'll want versioning enabled on the bucket for auditing and recovery purposes.

2.  **IAM Role for CodeBuild:** CodeBuild needs permissions to access the S3 bucket (read student code, write results) and to push logs to CloudWatch.  We will create an IAM Role with the necessary policies.

3.  **CodeBuild Project:**  This is the core component.  The CodeBuild project will define the build environment (using a Docker image, likely one with the necessary compilers/interpreters to run the student code), the build commands (instructions for fetching code, building, testing, and producing results) and the source location (GitHub). It will also use the IAM role we created.

4.  **GitHub Connection (AWS CodeStar Connections):** To allow CodeBuild to access the GitHub Repository, we need a connection to GitHub. If it doesn't already exist, we create it.

5.  **CloudWatch Logs:** CodeBuild automatically sends logs to CloudWatch, we may need specific permissions for CodeBuild to send logs.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# 1. S3 Bucket for code storage and results
resource "aws_s3_bucket" "autograder_bucket" {
  bucket = "cs-autograder-bucket-${random_id.rand.hex}" # unique name
  versioning {
    enabled = true
  }
}

resource "random_id" "rand" {
  byte_length = 8
}

# 2. IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "cs-autograder-codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      }
    ]
  })
}

resource "aws_iam_policy" "codebuild_s3_policy" {
  name = "cs-autograder-s3-policy"
  description = "Policy granting CodeBuild access to the S3 bucket"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
          "arn:aws:s3:::${aws_s3_bucket.autograder_bucket.bucket}",
          "arn:aws:s3:::${aws_s3_bucket.autograder_bucket.bucket}/*"
        ]
      },
      {
        Action = [
          "s3:PutObject"
        ],
        Effect   = "Allow",
        Resource = [
          "arn:aws:s3:::${aws_s3_bucket.autograder_bucket.bucket}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "codebuild_s3_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_s3_policy.arn
}

resource "aws_iam_policy_attachment" "codebuild_cloudwatch_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildDeveloperAccess"
}

# 3. CodeBuild Project
resource "aws_codebuild_project" "autograder_project" {
  name         = "cs-autograder-project"
  description  = "CodeBuild project for autograding student submissions"
  source {
    type             = "GITHUB"
    location         = "https://github.com/<your-org>/<your-repo>"  # Replace with your repository URL
    git_clone_depth = 10
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:7.0" #Choose appropriate image
    type         = "LINUX"
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-autograder-logs"
      stream_name = "cs-autograder-log-stream"
    }
  }

  service_role = aws_iam_role.codebuild_role.arn
}

