  bucket = "cat-pictures-bucket-unique-name" # Replace with a unique bucket name
  acl    = "private"

  tags = {
    Name        = "Cat Pictures Bucket"
    Environment = "dev"
  }
}

# IAM Role for Lambda Function
resource "aws_iam_role" "lambda_role" {
  name               = "lambda_cat_pictures_role"
  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "lambda.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

# IAM Policy for Lambda to access S3
resource "aws_iam_policy" "lambda_s3_policy" {
  name        = "lambda_s3_access_policy"
  description = "Policy to allow Lambda to access S3 bucket"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "s3:GetObject",
        "s3:PutObject",
        "s3:DeleteObject"
      ],
      "Resource": [
        "${aws_s3_bucket.cat_pictures_bucket.arn}/*"
      ]
    },
    {
      "Effect": "Allow",
      "Action": "s3:ListBucket",
      "Resource": "${aws_s3_bucket.cat_pictures_bucket.arn}"
    }
  ]
}
EOF
}

# Attach the S3 policy to the Lambda role
resource "aws_iam_role_policy_attachment" "lambda_s3_attachment" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_s3_policy.arn
}

# Lambda Function (Placeholder - Replace with your actual code)
resource "aws_lambda_function" "cat_pictures_lambda" {
  function_name = "CatPicturesLambda"
  role          = aws_iam_role.lambda_role.arn
