  runtime       = "python3.9"   # Choose your preferred runtime
  zip_file      = "lambda_function.zip" # Replace with your deployed zip file

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pictures_bucket.bucket
    }
  }
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_pictures_api" {
  name        = "CatPicturesAPI"
  description = "API for uploading and retrieving cat pictures"
}

# API Gateway Resource for /upload
resource "aws_api_gateway_resource" "upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_pictures_api.id
  path_part   = "upload"
}

# API Gateway Method for POST /upload
resource "aws_api_gateway_method" "upload_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_pictures_api.id
  resource_id   = aws_api_gateway_resource.upload_resource.id
  http_method   = "POST"
  integration_type = "AWS_PROXY"

  integration {
    type                     = "AWS_PROXY"
    lambda_function_arn      = aws_lambda_function.cat_pictures_lambda.arn
    lambda_function_name     = aws_lambda_function.cat_pictures_lambda.function_name
  }
}

# API Gateway Resource for /cat
