  region = "us-east-1" # Replace with your desired region
}

# 1. EC2 Key Pair
resource "aws_key_pair" "deployer_key" {
  key_name   = "my-ec2-key" # Changed to a static name
  public_key = "ssh-rsa AAAAB3NzaC1yc2EAAAADAQABAAABAQ..." # Replace with your public key
}

# 2. Security Group
resource "aws_security_group" "ec2_sg" {
  name        = "ec2-sg"
  description = "Allow SSH and HTTP/HTTPS access"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: Restrict to your IP for security!
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}


# 3. EC2 Instance
resource "aws_instance" "example" {
  ami           = "ami-0c55b2ab30bec84c3" # Amazon Linux 2 AMI - us-east-1. Replace for other regions
  instance_type = "t2.micro"
  key_name      = aws_key_pair.deployer_key.key_name
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  tags = {
    Name = "MyEC2Instance"
  }
}

# 4. Backup Vault
resource "aws_backup_vault" "example" {
