}

provider "aws" {
  region = "us-east-1"  # Replace with your desired region
}

# S3 Bucket for storing video content
resource "aws_s3_bucket" "video_bucket" {
  bucket = "your-unique-video-bucket-name" # Replace with a globally unique name
  acl    = "private"

  versioning {
    enabled = true
  }

  # Disable website configuration as CloudFront serves content directly
  # website {
  #   index_document = "index.html"
  #   error_document = "error.html"
  # }
}

# CloudFront Origin Access Identity
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for video bucket"
}

# CloudFront Distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name               = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_id                 = "S3-video-origin"
    s3_bucket_access {
      access_type = "private"
      bucket      = aws_s3_bucket.video_bucket.bucket
    }
  }

  default_root_object = "index.html"  # or a default video file name

  viewer_protocol_policy = "redirect-to-https"

  price_class = "PriceClass_100" # Adjust according to your needs

  enabled         = true
  comment         = "CloudFront distribution for video streaming"

  default_cache_behavior {
    target_origin_id = "S3-video-origin" #reference the origin id declared above
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    forwarded_values {
      query_string = false # Adjust as needed
      cookies      = { forward = "none" }
    }
  }

  restrictions {
    geo_restriction {
      restriction_type = "none" # Adjust as needed - ideally use whitelist for security
      quantity         = 0
    }
  }

}

# IAM policy to grant CloudFront access to the S3 bucket
resource "aws_s3_bucket_policy" "video_bucket_policy" {
  bucket = aws_s3_bucket.video_bucket.bucket
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = "s3:GetObject",
        Principal = {
          AWS = [aws_cloudfront_origin_access_identity.oai.canonical_user_id]
        },
        Resource = "${aws_s3_bucket.video_bucket.arn}/*",
      },
    ],
  })
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "video_content" {
  bucket_prefix = "video-content-"
}

resource "aws_s3_object" "put_website" {
  bucket = aws_s3_bucket.video_content.bucket
  key = "index.html"
  source = "./supplement/index.html"
  content_type = "text/html"
}

resource "aws_s3_object" "put_website_css" {
  bucket = aws_s3_bucket.video_content.bucket
  key = "css/style.css"
  source = "./supplement/css/style.css"
  content_type = "text/css"
}

resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.my_distribution.arn
          }
        }
      }
    ]
  })
}


locals {
  s3_origin_id = "s3_video_content_origin"
}

resource "aws_cloudfront_origin_access_control" "s3_oac" {
  name                              = "s3-oac"
  description                       = "aws access control policy"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

resource "aws_cloudfront_distribution" "my_distribution" {
  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.s3_oac.id
    origin_id                = local.s3_origin_id
  }

  enabled             = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = local.s3_origin_id

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "allow-all"
  }

  price_class = "PriceClass_200"

  restrictions {
    geo_restriction {
      restriction_type = "whitelist"
      locations        = ["US", "CA", "GB", "DE"]
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# Route53
resource "aws_route53_zone" "my_zone" {
  name = "my-test-cloudfront.com"
}

resource "aws_route53_record" "cdn_ipv4" {
  type    = "A"
  name    = "cdn"
  zone_id = aws_route53_zone.my_zone.zone_id

  alias {
    name                   = aws_cloudfront_distribution.my_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.my_distribution.hosted_zone_id
    evaluate_target_health = true
  }
}

response:
Okay, let's break down the requirements for a video streaming site infrastructure using CloudFront and S3 on AWS.

1.  **S3 Bucket:** We need an S3 bucket to store the video content. It should be configured for static website hosting to directly serve the video files, but we'll disable website hosting as CloudFront will be handling the serving. We'll also enable versioning for rollbacks and data protection.

2.  **CloudFront Distribution:** A CloudFront distribution will cache and deliver the video content globally. We'll configure it to use the S3 bucket as its origin. Important configurations include:
    *   **Origin Access Identity (OAI):**  Restrict direct access to the S3 bucket, forcing requests to go through CloudFront.
    *   **Viewer Protocol Policy:**  Redirect all HTTP requests to HTTPS.
    *   **Price Class:** Consider the price class based on the target audience geographically (e.g., `PriceClass_100` for North America and Europe, `PriceClass_200` for global coverage).
    *   **Default Root Object:** Set this to the default video file or index.html
    *   **Caching:** Configure the appropriate caching settings for the video content (e.g., cache duration).

3.  **IAM Role (needed for OAI):** ACloudFront `Origin Access Identity` needs associated permissions to read from the S3 bucket.

Here's the Terraform configuration to achieve this:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Replace with your desired region
}

# S3 Bucket for storing video content
resource "aws_s3_bucket" "video_bucket" {
  bucket = "your-unique-video-bucket-name" # Replace with a globally unique name
  acl    = "private"

  versioning {
    enabled = true
  }

  # Disable website configuration as CloudFront serves content directly
  # website {
  #   index_document = "index.html"
  #   error_document = "error.html"
  # }
}

# CloudFront Origin Access Identity
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for video bucket"
}

# CloudFront Distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name               = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_id                 = "S3-video-origin"
    s3_bucket_access {
      access_type = "private"
      bucket      = aws_s3_bucket.video_bucket.bucket
    }
  }

  default_root_object = "index.html"  # or a default video file name

  viewer_protocol_policy = "redirect-to-https"

  price_class = "PriceClass_100" # Adjust according to your needs

  enabled         = true
  comment         = "CloudFront distribution for video streaming"

  default_cache_behavior {
    target_origin_id = "S3-video-origin" #reference the origin id declared above
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    forwarded_values {
      query_string = false # Adjust as needed
      cookies      = { forward = "none" }
    }
  }

  restrictions {
    geo_restriction {
      restriction_type = "none" # Adjust as needed - ideally use whitelist for security
      quantity         = 0
    }
  }

}

# IAM policy to grant CloudFront access to the S3 bucket
resource "aws_s3_bucket_policy" "video_bucket_policy" {
  bucket = aws_s3_bucket.video_bucket.bucket
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = "s3:GetObject",
        Principal = {
          AWS = [aws_cloudfront_origin_access_identity.oai.canonical_user_id]
        },
        Resource = "${aws_s3_bucket.video_bucket.arn}/*",
      },
    ],
  })
}
```

