response:
Okay, let's break down the Terraform configuration for a video streaming site using AWS CloudFront, Route 53, and S3.

**1. S3 Bucket:** We'll need an S3 bucket to store the video content.  It needs to be publicly readable (through CloudFront, not directly) and ideally versioned.

**2. CloudFront Distribution:**  This will be the CDN responsible for distributing the video content globally. It will pull content from the S3 bucket.  We'll configure an origin, behaviors, caching, and SSL certificate. We’ll use the AWS managed SSL certificate.

**3. Route 53 Record:**  We'll need a Route 53 record (a CNAME record, ideally) to point a domain name to the CloudFront distribution.

**4. IAM Role:** CloudFront needs permission to access the S3 bucket.  We'll create an IAM role and policy to allow this.

**5. ACM Certificate:** Because the application needs HTTPS, an ACM certificate is required for the CloudFront distribution.

Here's the Terraform configuration embodying these components:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Create an S3 bucket to store video content
resource "aws_s3_bucket" "video_bucket" {
  bucket = "video-streaming-bucket-unique" # Replace with a unique bucket name
  acl    = "private" # Important: Keep bucket private. CloudFront will access it.
  versioning {
    enabled = true
  }
}

# IAM Role for CloudFront to access S3
resource "aws_iam_role" "cloudfront_role" {
  name = "cloudfront-s3-access-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "cloudfront.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      }
    ]
  })
}

resource "aws_iam_policy" "cloudfront_s3_policy" {
  name        = "cloudfront-s3-policy"
  description = "Policy for CloudFront to access S3 bucket"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetObject"
        ],
        Effect   = "Allow",
        Resource = "${aws_s3_bucket.video_bucket.arn}/*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "cloudfront_s3_attachment" {
  role       = aws_iam_role.cloudfront_role.name
  policy_arn = aws_iam_policy.cloudfront_s3_policy.arn
}

# Create a CloudFront distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name               = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_id                 = "S3Origin"
    s3_origin_config {
      origin_access_identity = "origin-access-identity"
    }
  }

  default_root_object = "index.html"

  default_cache_behavior {
    target_origin_id = "S3Origin"
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods = ["GET", "HEAD"]
    cached_methods  = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies      = false
    }
  }

  price_class = "UseOnlyLowerPerSec"
  enabled = true

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# Route 53 Record
resource "aws_route53_zone" "primary" {
  name = "yourdomain.com" # Replace with your domain name
}

resource "aws_route53_record" "cloudfront_record" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "videos.yourdomain.com" # Replace with your desired subdomain
  type    = "CNAME"
  ttl     = "300"
  records = [aws_cloudfront_distribution.video_distribution.domain_name]
}
```

extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Replace with your desired AWS region
}

# S3 Bucket for Video Storage
resource "aws_s3_bucket" "video_bucket" {
  bucket = "video-streaming-bucket-${random_string(5, true, true)}"
  versioning {
    enabled = true
  }
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
  tags = {
    Name = "Video Streaming Bucket"
  }
}

# Origin Access Control (OAC)
resource "aws_cloudfront_origin_access_control" "oac" {
  name              = "video-oac"
  signing_behavior  = "always"
  origin_type       = "S3"
}


# S3 Bucket Policy to allow access from CloudFront using OAC
resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Grant CloudFront Origin Access Identity Service Principal Read Permissions"
        Effect    = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = [
          "s3:GetObject"
        ]
        Resource = "arn:aws:s3:::${aws_s3_bucket.video_bucket.bucket}/*"
      }
    ]
  })
}

# CloudFront Distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  domain_name               = "video.example.com" # Replace with your domain
  enabled                   = true
  comment                   = "CloudFront distribution for video streaming"

  origin {
    domain_name = aws_s3_bucket.video_bucket.bucket
    origin_id   = "S3Origin"

    s3_origin_config {
      origin_access_control = aws_cloudfront_origin_access_control.oac.id
    }
  }

  default_cache_behavior {
    target_origin_id = "S3Origin"
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods        = ["GET", "HEAD"]
    cached_methods         = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies      = false
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Name = "Video Streaming Distribution"
  }
}


# Route53 Hosted Zone
resource "aws_route53_zone" "video_zone" {
  name = "video.example.com" # Replace with your domain

}

# Route53 Record (Alias to CloudFront Distribution)
resource "aws_route53_record" "video_record" {
  zone_id = aws_route53_zone.video_zone.zone_id
  name    = "video.example.com" # Replace with your domain
  type    = "A"
  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = true
  }
}

output "cloudfront_domain_name" {
  value = aws_cloudfront_distribution.video_distribution.domain_name
}

output "route53_name_servers" {
  value = aws_route53_zone.video_zone.name_servers
}

