response:
Okay, let's break down the Terraform configuration needed for a video streaming site leveraging CloudFront, S3, Route53, and Origin Access Control.

1.  **S3 Bucket:** We'll start with an S3 bucket to store the video content. It needs versioning enabled for rollback capabilities. We'll enable server-side encryption for security.
2.  **Origin Access Control (OAC):** This is the modern replacement for Origin Access Identity (OAI). OAC provides secure access to the S3 bucket for CloudFront. We will create an OAC and configure the S3 bucket policy to allow CloudFront to access it via the OAC principal.
3.  **CloudFront Distribution:** This will be the core of our content delivery network (CDN). It will use the S3 bucket as its origin. We will configure caching behavior, enable HTTPS, and associate it with the OAC.
4.  **Route53 Zone:** A Route53 hosted zone will serve as the DNS zone for our subdomain, allowing us to map a user-friendly hostname to the CloudFront distribution.
5.  **Route53 Record:** Create an A record in Route53 pointing to the CloudFront distribution. We will use an alias record for this.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Replace with your desired AWS region
}

# S3 Bucket for Video Storage
resource "aws_s3_bucket" "video_bucket" {
  bucket = "video-streaming-bucket-${random_string(5, true, true)}"
  versioning {
    enabled = true
  }
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
  tags = {
    Name = "Video Streaming Bucket"
  }
}

# Origin Access Control (OAC)
resource "aws_cloudfront_origin_access_control" "oac" {
  name              = "video-oac"
  signing_behavior  = "always"
  origin_type       = "S3"
}


# S3 Bucket Policy to allow access from CloudFront using OAC
resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Grant CloudFront Origin Access Identity Service Principal Read Permissions"
        Effect    = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = [
          "s3:GetObject"
        ]
        Resource = "arn:aws:s3:::${aws_s3_bucket.video_bucket.bucket}/*"
      }
    ]
  })
}

# CloudFront Distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  domain_name               = "video.example.com" # Replace with your domain
  enabled                   = true
  comment                   = "CloudFront distribution for video streaming"

  origin {
    domain_name = aws_s3_bucket.video_bucket.bucket
    origin_id   = "S3Origin"

    s3_origin_config {
      origin_access_control = aws_cloudfront_origin_access_control.oac.id
    }
  }

  default_cache_behavior {
    target_origin_id = "S3Origin"
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods        = ["GET", "HEAD"]
    cached_methods         = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies      = false
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Name = "Video Streaming Distribution"
  }
}


# Route53 Hosted Zone
resource "aws_route53_zone" "video_zone" {
  name = "video.example.com" # Replace with your domain

}

# Route53 Record (Alias to CloudFront Distribution)
resource "aws_route53_record" "video_record" {
  zone_id = aws_route53_zone.video_zone.zone_id
  name    = "video.example.com" # Replace with your domain
  type    = "A"
  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = true
  }
}

output "cloudfront_domain_name" {
  value = aws_cloudfront_distribution.video_distribution.domain_name
}

output "route53_name_servers" {
  value = aws_route53_zone.video_zone.name_servers
}
```

