}

response:
Okay, let's break down this Terraform configuration request step-by-step. We need to create several resources:

1.  **CloudFront Origin Access Control (OAC):** This controls access to the S3 bucket.
2.  **CloudFront Distribution:** This serves content from the S3 bucket. It includes origin configuration, caching behaviors, pricing, geographic restrictions, and viewer certificate settings.
3.  **Route 53 Hosted Zone:**  This hosts the DNS records for the domain.
4.  **Route 53 Records:** These point the domain (or subdomain) to the CloudFront distribution.

Here's the complete Terraform configuration:

```hcl
resource "aws_cloudfront_origin_access_control" "oac" {
  name                          = "netflix-oac"
  origin_access_control_origin_type = "s3"
  signing_behavior              = "always"
  signing_protocol              = "sigv4"
}

resource "aws_cloudfront_distribution" "cdn" {
  comment                       = "CloudFront distribution for Netflix video content"

  origin {
    domain_name                = "netflix-video-bucket.s3.amazonaws.com" # Replace with your actual S3 bucket domain
    origin_id                  = "s3_video_content_origin"
    origin_access_control_id = aws_cloudfront_origin_access_control.oac.id
  }

  default_cache_behavior {
    allowed_methods            = ["GET", "HEAD"]
    cached_methods             = ["GET", "HEAD"]
    target_origin_id           = "s3_video_content_origin"
    viewer_protocol_policy     = "allow-all"
  }

  price_class                  = "PriceClass_200"

  restrictions {
    geo_restriction {
      restriction_type = "whitelist"
      locations        = ["US", "CA", "GB", "DE"]
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

resource "aws_route53_zone" "hosted_zone" {
  name = "netflix.com"
}

resource "aws_route53_record" "record1" {
  zone_id = aws_route53_zone.hosted_zone.zone_id
