}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# 1. VPC Module
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.1.1"

  name = "video-streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b", "us-east-1c"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  public_subnets  = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]

  enable_nat_gateway = true
  single_nat_gateway = true

  tags = {
    Terraform   = "true"
    Environment = "dev"
  }
}

# 2. Launch Template
resource "aws_launch_template" "video_streaming_launch_template" {
  name_prefix   = "video-streaming-lt-"
  image_id      = "ami-0c55b5418260e78a8" # Example Ubuntu 22.04 AMI - replace with desired AMI
  instance_type = "t3.medium"
  key_name      = "your-key-pair" # Replace with your key pair name
  security_group_ids = [aws_security_group.video_streaming_sg.id]
  iam_instance_profile {
    name = aws_iam_instance_profile.ec2_profile.name
  }

  network_interfaces {
    associate_public_ip_address = false
    security_groups = [aws_security_group.video_streaming_sg.id]
  }
}

# 3. IAM Role for EC2 Instances
resource "aws_iam_role" "ec2_role" {
  name               = "ec2-video-streaming-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_instance_profile" "ec2_profile" {
  name = "ec2-video-streaming-profile"
  role = aws_iam_role.ec2_role.name
}

# 4. Security Group
resource "aws_security_group" "video_streaming_sg" {
  name        = "video-streaming-sg"
  description = "Allow inbound traffic for video streaming"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow HTTP traffic"
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow HTTPS traffic"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow all outbound traffic"
  }
}

# 5. Application Load Balancer
resource "aws_lb" "video_streaming_lb" {
  name               = "video-streaming-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.video_streaming_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Name = "video-streaming-lb"
  }
}

resource "aws_lb_target_group" "video_streaming_tg" {
  name     = "video-streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id
  health_check {
    path = "/"
    port = "traffic"
  }
}

resource "aws_lb_listener" "video_streaming_listener" {
  load_balancer_arn = aws_lb.video_streaming_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_streaming_tg.arn
  }
}

# 6. EC2 Instances - Scale based on demand (example: 2 instances)
resource "aws_launch_template_version" "video_streaming_ltv" {
  launch_template_id = aws_launch_template.video_streaming_launch_template.id
  version_description = "Initial version"
}

resource "aws_autoscaling_group" "video_streaming_asg" {
  name                      = "video-streaming-asg"
  desired_capacity          = 2
  min_size                  = 1
  max_size                  = 3
  vpc_zone_identifier       = module.vpc.private_subnets
  launch_template {
    id      = aws_launch_template_version.video_streaming_ltv.id
    version = "$Latest"
  }
  target_group_arns = [aws_lb_target_group.video_streaming_tg.arn]
}

# 7. Route 53 Record

resource "aws_route53_record" "video_streaming_record" {
  zone_id = "YOUR_ROUTE53_ZONE_ID" # Replace with your Route 53 zone ID
  name    = "video.example.com" # Replace with your domain name
  type    = "A"
  ttl     = 300
  records = [aws_lb.video_streaming_lb.dns_name]
}

