    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Launch Template for EC2 Instances
resource "aws_launch_template" "video_instance_lt" {
  name_prefix   = "video-instance-lt-"
  image_id      = "ami-0c55bca456d74936c"  # Replace with a suitable AMI for your region.
