resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  skip_final_snapshot             = true
  allocated_storage               = 5
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

response:
Okay, let's break down the requirements to create a Terraform configuration for a secure PostgreSQL database instance on AWS.

1.  **VPC**: We need a VPC to launch the RDS instance into. I will assume it already exists and take the ID as a variable.
2.  **Subnets**: We need subnets within the VPC for high availability. I'll take a list of subnet IDs as a variable.
3.  **Security Group**:  A security group is needed to control access to the database. We’ll allow PostgreSQL traffic (default port 5432) from a specified CIDR block, and potentially from within the VPC itself.
4.  **KMS Key**: We'll use a KMS key for encrypting the database storage. I'll assume an existing key and take the key ID as a variable.
5.  **RDS Instance**:  The core resource is the RDS instance. We’ll configure it with the engine version, instance class, storage size, allocated storage type, multi-AZ, database name, master username, and password (using a variable for the password and encouraging its secure management).
6.  **Parameter Group**: A custom parameter group lets us modify PostgreSQL configuration. We will create a custom parameter group and associate the RDS instance with it.
7. **Tags**: Add tags for resource identification.

Here's the Terraform code:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

variable "vpc_id" {
  type        = string
  description = "The ID of the VPC to launch the RDS instance into."
}

variable "subnet_ids" {
  type        = list(string)
  description = "A list of subnet IDs to launch the RDS instance into."
}

variable "kms_key_id" {
  type        = string
  description = "The ID of the KMS key to use for encryption."
}

variable "db_name" {
  type        = string
  description = "The name of the database to create."
  default     = "mydb"
}

variable "db_username" {
  type        = string
  description = "The username for the database."
  default     = "admin"
}

variable "db_password" {
  type        = string
  description = "The password for the database.  Use a secure way to manage this."
  sensitive   = true # Mark as sensitive to prevent accidental exposure in state
}

variable "instance_class" {
  type        = string
  description = "The instance class for the RDS instance."
  default     = "db.t3.medium"
}

variable "allocated_storage" {
  type        = number
  description = "The amount of allocated storage in GB."
  default     = 20
}

variable "engine_version" {
  type        = string
  description = "The PostgreSQL engine version."
  default     = "15.4"
}

variable "environment" {
  type        = string
  description = "The environment (e.g., dev, staging, prod)."
  default     = "dev"
}

# Security Group
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: Restrict to specific IPs in production!
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name        = "rds-sg-${var.environment}"
    Environment = var.environment
  }
}

# KMS Key (assuming it already exists)

# Custom Parameter Group
resource "aws_db_parameter_group" "pg_parameter_group" {
  name   = "custom-pg-parameter-group"
  family = "postgres${substr(var.engine_version, 0, 2)}"  #Dynamically determine Postgres family
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "shared_buffers"
    value = "128MB"
  }
}

# RDS Instance
resource "aws_db_instance" "default" {
  allocated_storage    = var.allocated_storage
  engine               = "postgres"
  engine_version       = var.engine_version
  instance_class       = var.instance_class
  name                 = "postgres-db"
  username             = var.db_username
  password             = var.db_password
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  kms_key_id           = var.kms_key_id
  multi_az             = true
  db_name              = var.db_name
  parameter_group_name = aws_db_parameter_group.pg_parameter_group.name
  skip_final_snapshot  = true # Change to false in production.

  tags = {
    Name        = "postgres-db-${var.environment}"
    Environment = var.environment
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "postgres-subnet-group"
  subnet_ids = var.subnet_ids
  tags = {
    Name        = "postgres-subnet-group-${var.environment}"
    Environment = var.environment
  }
}
```

