response:
Okay, let's break down the requirements and then generate the Terraform configuration.

1.  **VPC and Subnets:** The problem states the database should be provisioned within a *specified* VPC. I will assume that the VPC ID and subnet IDs are provided as variables. This makes the code reusable.
2.  **RDS Instance:** We'll use `aws_db_instance` to create the PostgreSQL instance.
3.  **PostgreSQL Version:** The version is fixed at 15, so we'll specify `engine_version = "15"`.
4.  **Storage Size:** The storage size is 50GB, so `allocated_storage = 50`.
5.  **Multi-AZ:** To ensure high availability, we’ll set `multi_az = true`.
6.  **KMS Encryption:** We need to enable encryption at rest using a KMS key. We'll use `aws_kms_key` to create one and reference its ARN in the RDS instance config.  The KMS key will need an IAM policy to allow the RDS service to access it.
7.  **Custom Parameter Group:** We’ll create a custom parameter group using `aws_db_parameter_group`.  We can define parameters within this group. The problem doesn't specify *what* parameters to define, so I'll leave it as an empty parameter group for now.
8.  **Security Group:** A security group (`aws_security_group`) will control access to the database.  We'll allow PostgreSQL traffic (port 5432) from within the VPC.
9. **Variables:** We will define variables for the VPC ID, subnets, KMS key name, and instance identifier for flexibility.

Now, let's combine these steps into a Terraform configuration.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

variable "vpc_id" {
  type        = string
  description = "The ID of the VPC where the database will be created."
}

variable "subnet_ids" {
  type        = list(string)
  description = "A list of subnet IDs where the database will be created."
}

variable "kms_key_name" {
  type        = string
  description = "The name of the KMS key to use for encryption."
  default     = "postgresql-key"
}

variable "db_instance_identifier" {
  type        = string
  description = "The identifier for the database instance."
  default     = "postgres-db"
}

# Create a KMS key
resource "aws_kms_key" "postgres_kms_key" {
  description             = "KMS key for encrypting PostgreSQL database"
  key_usage               = "ENCRYPT_DECRYPT"
  policy                  = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          Service = "rds.amazonaws.com"
        },
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ],
        Resource = "*" # Be more specific in production.
      }
    ]
  })
  tags = {
    Name = var.kms_key_name
  }
}

# Create a custom parameter group
resource "aws_db_parameter_group" "postgres_param_group" {
  name        = "${var.db_instance_identifier}-param-group"
  family      = "postgres15"
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "log_statement"
    value = "all"

  }
}


# Create a security group
resource "aws_security_group" "postgres_sg" {
  name        = "${var.db_instance_identifier}-sg"
  description = "Security group for PostgreSQL database"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Ideally, restrict to your application's source IPs or internal subnet CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create the RDS instance
resource "aws_db_instance" "postgres_db" {
  allocated_storage      = 50
  engine                 = "postgres"
  engine_version         = "15"
  instance_class         = "db.t3.medium" # Choose an appropriate instance class.
  name                   = var.db_instance_identifier
  password               = "your_password" # Replace with a strong password.  Consider using Secrets Manager.
  username               = "your_username" # Replace with your desired username.
  db_subnet_group_name   = "default"  # consider creating custom db subnet group

  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  subnet_ids             = var.subnet_ids
  multi_az               = true
  skip_final_snapshot    = true # Set to true for testing/dev. Consider removing in Prod.
  kms_key_id             = aws_kms_key.postgres_kms_key.arn
  db_parameter_group_name = aws_db_parameter_group.postgres_param_group.name
}
```

