  db_subnet_group_name = aws_db_subnet_group.default.name
  publicly_accessible  = true # Important for testing and Airbyte access

  skip_final_snapshot  = true # Adjust as needed for production

  tags = {
    Name = "Airbyte PostgreSQL Test Instance"
  }
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_db_subnet_group" "db-subnet-group" {
  name       = "db-subnet-group"
  subnet_ids = module.vpc.public_subnets
}

resource "aws_security_group" "db-sg" {
  name = "db-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  skip_final_snapshot             = true
  allocated_storage               = 500
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

response:
Okay, let's break down the requirements and translate them into a Terraform configuration.

1.  **RDS Instance:** We need to create an AWS RDS instance running PostgreSQL 15.
2.  **Storage:** The instance should have 500GB of storage.
3.  **Public Subnets:** The RDS instance needs to reside within designated public subnets. This implies we'll need to figure out a way to pass these subnet IDs to the Terraform configuration (either through variables or hardcoding, but variables are preferred).
4.  **Airbyte Connector Testing:**  The instance is for Airbyte connector testing. This implies we might also want to configure access control (security groups) to allow access from Airbyte's testing infrastructure, but for now we'll focus on the core RDS setup.
5.  **Managed Settings/Low Maintenance:** This points towards using the default managed settings for backups, patching, and minor version upgrades. We can leverage the `default` values for some settings.

Here’s the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired AWS region
}

variable "db_subnet_group_name" {
  type        = string
  description = "The name of the DB subnet group"
}

variable "db_instance_identifier" {
  type        = string
  description = "The identifier for the DB instance."
  default     = "airbyte-postgres-test"
}

variable "public_subnets" {
  type        = list(string)
  description = "A list of public subnet IDs."
}

variable "master_username" {
  type        = string
  description = "The master username for the database."
  sensitive   = true
}

variable "master_password" {
  type        = string
  description = "The master password for the database."
  sensitive   = true
}

resource "aws_db_subnet_group" "default" {
  name       = var.db_subnet_group_name
  subnet_ids = var.public_subnets
}


resource "aws_rds_instance" "default" {
  allocated_storage    = 500
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.m5.large" # Choose an appropriate instance class
  name                 = var.db_instance_identifier
  username             = var.master_username
  password             = var.master_password
  db_subnet_group_name = aws_db_subnet_group.default.name
  publicly_accessible  = true # Important for testing and Airbyte access

  skip_final_snapshot  = true # Adjust as needed for production

  tags = {
    Name = "Airbyte PostgreSQL Test Instance"
  }
}
```

