Okay, let's break down this request and build the Terraform configuration.

1.  **VPC and Subnets:** We'll need a VPC to house the RDS cluster and the RDS Proxy. We'll create public and private subnets for high availability.

2.  **Security Groups:** Create separate Security Groups for the RDS cluster and the RDS Proxy, controlling inbound and outbound traffic. The proxy Security Group should allow inbound traffic from the application servers (which would typically be in a separate Security Group - we'll set the ingress to 0.0.0.0/0 for now but ideally this should be restricted).  The RDS security group will only allow access from the proxy.

3.  **RDS Cluster:** We'll define an Aurora MySQL cluster with a specified instance size, engine version, and other necessary configuration.

4.  **RDS Proxy:**  We'll create an RDS Proxy, associating it with the RDS cluster, VPC, subnets, and security group. We'll set the `idle_client_timeout` to 1800 seconds and disable debug logging.

5.  **IAM Role:** An IAM role needs to be created and attached to the RDS Proxy to authorize it to access the Secrets Manager secret.

6.  **Secrets Manager:** A secret will be created in Secrets Manager to hold the database credentials.

7.  **Outputs:** Important outputs like the RDS endpoint, cluster identifier, and proxy endpoint will be exposed.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# 1. VPC and Subnets
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "rds-vpc"
  }
}

resource "aws_subnet" "public_subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "rds-public-subnet-1"
  }
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  map_public_ip_on_launch = true
  tags = {
    Name = "rds-public-subnet-2"
  }
}

resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "rds-private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.4.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "rds-private-subnet-2"
  }
}

# 2. Security Groups
resource "aws_security_group" "rds_sg" {
  name        = "rds-sg"
  description = "Security group for RDS cluster"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.proxy_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}


resource "aws_security_group" "proxy_sg" {
  name        = "proxy-sg"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Ideally restrict this to your application servers
  }
}

# 3. RDS Cluster
resource "aws_rds_cluster" "default" {
  cluster_identifier = "aurora-mysql-cluster"
  engine             = "aurora-mysql"
  engine_version     = "5.7.mysql_aurora.2.10.2"
  database_name      = "mydb"
  master_username    = "admin"
  master_password    = "changeme" # Replace with a strong password or use Secrets Manager
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name = aws_db_subnet_group.default.name
  skip_final_snapshot = true # For demonstration purposes
}

resource "aws_db_subnet_group" "default" {
  name       = "aurora-subnets"
  subnet_ids = [
    aws_subnet.private_subnet_1.id,
    aws_subnet.private_subnet_2.id,
  ]
}

# 4. RDS Proxy
resource "aws_rds_proxy" "default" {
  proxy_identifier = "my-rds-proxy"
  engine_family    = "MYSQL"
  role_arn         = aws_iam_role.proxy_role.arn
  vpc_subnet_ids   = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  security_group_ids = [aws_security_group.proxy_sg.id]
  db_cluster_identifier = aws_rds_cluster.default.id
  idle_client_timeout = 1800
  enable_idle_client_timeout = true
  auth_schemes = ["PASSWORD"]
  require_tls = false
  dial_option_timeout_in_seconds = 30
}

# 5. IAM Role for RDS Proxy
resource "aws_iam_role" "proxy_role" {
  name = "rds-proxy-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "rds.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ],
  })
}

resource "aws_iam_policy" "proxy_policy" {
  name        = "rds-proxy-policy"
  description = "Policy for RDS Proxy to access Secrets Manager"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ],
        Effect   = "Allow",
        Resource = "*"  # Restrict this to your secret ARN in production
      },
    ],
  })
}

resource "aws_iam_role_policy_attachment" "proxy_policy_attachment" {
  role       = aws_iam_role.proxy_role.name
  policy_arn = aws_iam_policy.proxy_policy.arn
}


# 6. Secrets Manager (Example)
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "db-credentials"
  description = "Database credentials"
  tags = {
    Name = "db-credentials"
  }
}

# Outputs
output "rds_endpoint" {
  value = aws_rds_cluster.default.endpoint
}

output "rds_cluster_identifier" {
  value = aws_rds_cluster.default.cluster_identifier
}

output "rds_proxy_endpoint" {
  value = aws_rds_proxy.default.endpoint
}
