    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. IAM Role for RDS to access Secrets Manager
resource "aws_iam_role" "rds_secrets_manager_role" {
  name               = "rds-secrets-manager-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "rds.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      }
    ]
  })
}

resource "aws_iam_policy" "rds_secrets_manager_policy" {
  name        = "rds-secrets-manager-policy"
  description = "Allow RDS to read secrets from Secrets Manager"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ],
        Effect   = "Allow",
        Resource = "*" # Ideally, restrict to specific secret ARN
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_secrets_manager_attachment" {
  role       = aws_iam_role.rds_secrets_manager_role.name
  policy_arn = aws_iam_policy.rds_secrets_manager_policy.arn
}

# 4. Secrets Manager
resource "aws_secretsmanager_secret" "rds_secret" {
  name = "rds-db-credentials"
  rotation_configuration {
    rotate_immediately = false
    rotation_lambda_arn = ""  # Optional: Lambda function for automatic rotation
  }
}

# 5. RDS Aurora Cluster
resource "aws_rds_cluster" "default" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.08.0"
  master_username         = "admin"  # Consider using Secrets Manager directly, but for simplicity
  master_password         = "ReplaceWithStrongPassword"
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot = true

  scaling_configuration {
    auto_pause               = false
    max_capacity             = 2
    min_capacity             = 1
    seconds_until_auto_pause = 300
  }
}

resource "aws_db_subnet_group" "default" {
  name       = "aurora-db-subnet-group"
  subnet_ids = [aws_subnet.rds_subnet_1.id, aws_subnet.rds_subnet_2.id]
}

# 6. RDS Aurora Database
resource "aws_rds_database" "default" {
  cluster_identifier = aws_rds_cluster.default.id
  database_name      = "mydb"
}

# 7. Database Proxy
resource "aws_rds_db_proxy" "default" {
  db_proxy_name = "my-db-proxy"
  engine_family = "MYSQL"
  role_arn      = aws_iam_role.rds_secrets_manager_role.arn
  vpc_subnet_ids = [aws_subnet.rds_subnet_1.id, aws_subnet.rds_subnet_2.id]
  target_group_arn = aws_db_proxy_target_group.default.arn

  auth {
    auth_scheme = "SECRET"
    secret_arn = aws_secretsmanager_secret.rds_secret.arn
  }
}

# 8. Associate Proxy with Target Group
resource "aws_db_proxy_target_group" "default" {
  name        = "my-db-proxy-target-group"
  engine      = "MYSQL"
  db_cluster_identifier = aws_rds_cluster.default.id
}

