terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name                 = "main-vpc"
  cidr                 = "10.0.0.0/16"
  azs                  = data.aws_availability_zones.available.names
  private_subnets      = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets       = ["10.0.3.0/24", "10.0.4.0/24"]
}

resource "aws_security_group" "rds-proxy-sg" {
  name        = "rds-proxy-sg"
  vpc_id      = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-proxy-sg-ingress-rule" {
  from_port       = 3306
  to_port         = 3306
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.rds-proxy-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-proxy-sg-egress-rule" {
  from_port       = 3306
  to_port         = 3306
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.rds-proxy-sg.id
}

resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = module.vpc.private_subnets
}

resource "aws_rds_cluster" "example" {
  cluster_identifier      = "example-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.08.0"
  master_username         = "myusername"
  master_password         = "password123"
  database_name           = "exampledb"
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.rds-proxy-sg.id]
  db_subnet_group_name    = aws_db_subnet_group.main.name
}

resource "aws_secretsmanager_secret" "db-credentials" {
  name_prefix = "db-credentials-"
}

resource "aws_secretsmanager_secret_version" "db-credentials-version" {
  secret_id     = aws_secretsmanager_secret.db-credentials.id
  secret_string = jsonencode({
    username = aws_rds_cluster.example.master_username
    password = aws_rds_cluster.example.master_password
  })
}

resource "aws_iam_role" "rds-proxy-role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "rds-proxy-policy" {
  name        = "rds-proxy-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
        ]
        Resource = [
          "${aws_secretsmanager_secret_version.db-credentials-version.arn}",
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach-proxy-policy" {
  role       = aws_iam_role.rds-proxy-role.name
  policy_arn = aws_iam_policy.rds-proxy-policy.arn
}

resource "aws_db_proxy" "example" {
  name                   = "example-proxy"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds-proxy-role.arn
  vpc_security_group_ids = [aws_security_group.rds-proxy-sg.id]
  vpc_subnet_ids         = module.vpc.private_subnets

  auth {
    auth_scheme  = "SECRETS"
    secret_arn   = aws_secretsmanager_secret.db-credentials.arn
    iam_auth     = "DISABLED"
  }
}

resource "aws_db_proxy_default_target_group" "example" {
  db_proxy_name = aws_db_proxy.example.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    init_query                   = "SET x=1, y=2"
    max_connections_percent      = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = ["EXCLUDE_VARIABLE_SETS"]
  }
}

resource "aws_db_proxy_target" "example" {
  db_cluster_identifier = aws_rds_cluster.example.cluster_identifier
  db_proxy_name          = aws_db_proxy.example.name
  target_group_name      = aws_db_proxy_default_target_group.example.name
}

response:
Okay, let's break down the requirements for creating an AWS RDS Aurora MySQL cluster with a proxy, VPC, subnets, security groups, IAM roles, and Secrets Manager integration using Terraform.

1.  **VPC and Subnets:** We'll need a VPC and at least two private subnets across different Availability Zones for high availability.

2.  **Security Groups:** A security group to allow access to the RDS cluster from the proxy, and another for the proxy itself to allow access from applications.

3.  **IAM Roles:**  An IAM role for RDS to access Secrets Manager to retrieve credentials.

4.  **Secrets Manager:** Storing the database master username and password in Secrets Manager.

5.  **RDS Aurora Cluster:** The core Aurora MySQL cluster definition, specifying engine, version, instance type, and using the created subnets and security groups.

6.  **RDS Aurora Database:** Create a database within the cluster.

7.  **Database Proxy:** Create a database proxy to manage connections to the Aurora cluster.

8.  **Associate Proxy with Target Group:** Associate the Proxy with a target group that points to the Aurora cluster endpoint.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# 1. VPC and Subnets
resource "aws_vpc" "rds_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "rds-vpc"
  }
}

resource "aws_subnet" "rds_subnet_1" {
  vpc_id     = aws_vpc.rds_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  tags = {
    Name = "rds-subnet-1"
  }
}

resource "aws_subnet" "rds_subnet_2" {
  vpc_id     = aws_vpc.rds_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired AZ
  tags = {
    Name = "rds-subnet-2"
  }
}

# 2. Security Groups
resource "aws_security_group" "rds_sg" {
  name        = "rds-sg"
  description = "Allow access to RDS from Proxy"
  vpc_id      = aws_vpc.rds_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_group_id = aws_security_group.proxy_sg.id
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "proxy_sg" {
  name        = "proxy-sg"
  description = "Allow access to Proxy from applications"
  vpc_id      = aws_vpc.rds_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Adjust CIDR block to your application's access range
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. IAM Role for RDS to access Secrets Manager
resource "aws_iam_role" "rds_secrets_manager_role" {
  name               = "rds-secrets-manager-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "rds.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      }
    ]
  })
}

resource "aws_iam_policy" "rds_secrets_manager_policy" {
  name        = "rds-secrets-manager-policy"
  description = "Allow RDS to read secrets from Secrets Manager"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ],
        Effect   = "Allow",
        Resource = "*" # Ideally, restrict to specific secret ARN
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_secrets_manager_attachment" {
  role       = aws_iam_role.rds_secrets_manager_role.name
  policy_arn = aws_iam_policy.rds_secrets_manager_policy.arn
}

# 4. Secrets Manager
resource "aws_secretsmanager_secret" "rds_secret" {
  name = "rds-db-credentials"
  rotation_configuration {
    rotate_immediately = false
    rotation_lambda_arn = ""  # Optional: Lambda function for automatic rotation
  }
}

# 5. RDS Aurora Cluster
resource "aws_rds_cluster" "default" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.08.0"
  master_username         = "admin"  # Consider using Secrets Manager directly, but for simplicity
  master_password         = "ReplaceWithStrongPassword"
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot = true

  scaling_configuration {
    auto_pause               = false
    max_capacity             = 2
    min_capacity             = 1
    seconds_until_auto_pause = 300
  }
}

resource "aws_db_subnet_group" "default" {
  name       = "aurora-db-subnet-group"
  subnet_ids = [aws_subnet.rds_subnet_1.id, aws_subnet.rds_subnet_2.id]
}

# 6. RDS Aurora Database
resource "aws_rds_database" "default" {
  cluster_identifier = aws_rds_cluster.default.id
  database_name      = "mydb"
}

# 7. Database Proxy
resource "aws_rds_db_proxy" "default" {
  db_proxy_name = "my-db-proxy"
  engine_family = "MYSQL"
  role_arn      = aws_iam_role.rds_secrets_manager_role.arn
  vpc_subnet_ids = [aws_subnet.rds_subnet_1.id, aws_subnet.rds_subnet_2.id]
  target_group_arn = aws_db_proxy_target_group.default.arn

  auth {
    auth_scheme = "SECRET"
    secret_arn = aws_secretsmanager_secret.rds_secret.arn
  }
}

# 8. Associate Proxy with Target Group
resource "aws_db_proxy_target_group" "default" {
  name        = "my-db-proxy-target-group"
  engine      = "MYSQL"
  db_cluster_identifier = aws_rds_cluster.default.id
}
```

