  auth {
    auth_scheme  = "SECRETS"
    secret_arn   = aws_secretsmanager_secret.db-credentials.arn
    iam_auth     = "DISABLED"
  }
}

resource "aws_db_proxy_default_target_group" "example" {
  db_proxy_name = aws_db_proxy.example.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    init_query                   = "SET x=1, y=2"
    max_connections_percent      = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = ["EXCLUDE_VARIABLE_SETS"]
  }
}

resource "aws_db_proxy_target" "example" {
  db_cluster_identifier = aws_rds_cluster.example.cluster_identifier
  db_proxy_name          = aws_db_proxy.example.name
  target_group_name      = aws_db_proxy_default_target_group.example.name
}

response:
Okay, let's break down this request and generate the Terraform configuration.

1.  **VPC & Subnets:** We'll need a VPC and at least two subnets (preferably in different Availability Zones) for high availability.
2.  **Security Groups:** A security group to allow traffic to the RDS cluster from the RDS Proxy and potentially from the VPC itself for administrative tasks.
3.  **IAM Roles:** An IAM role for RDS to access Secrets Manager to retrieve database credentials.
4.  **Secrets Manager:** Store database username and password securely in AWS Secrets Manager.
5.  **RDS Proxy:**  Create an RDS Proxy to manage connections to the Aurora cluster.
6.  **Aurora MySQL Cluster:**  The core Aurora MySQL cluster itself, configured with a chosen instance size and version.
7.  **Final Snapshot:** Configure the cluster to take a final snapshot upon deletion.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# 1. VPC and Subnets
resource "aws_vpc" "rds_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "rds-vpc"
  }
}

resource "aws_subnet" "rds_subnet_1" {
  vpc_id            = aws_vpc.rds_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  tags = {
    Name = "rds-subnet-1"
  }
}

resource "aws_subnet" "rds_subnet_2" {
  vpc_id            = aws_vpc.rds_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired AZ
  tags = {
    Name = "rds-subnet-2"
  }
}

# 2. Security Group
resource "aws_security_group" "rds_sg" {
  name        = "rds-sg"
  description = "Allow inbound traffic to RDS cluster"
  vpc_id      = aws_vpc.rds_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.rds_sg.id] # Allow traffic from within the security group for proxy
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

# 3. IAM Role for RDS
resource "aws_iam_role" "rds_role" {
  name               = "rds-secrets-manager-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "rds.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      }
    ]
  })
}

resource "aws_iam_policy" "rds_secrets_manager_policy" {
  name        = "rds-secrets-manager-policy"
  description = "Allow RDS to access Secrets Manager"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ],
        Effect   = "Allow",
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_secrets_manager_attachment" {
  role       = aws_iam_role.rds_role.name
  policy_arn = aws_iam_policy.rds_secrets_manager_policy.arn
}

# 4. Secrets Manager
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "rds-db-credentials"

  tags = {
    Name = "RDS DB Credentials"
  }
}

# 5. RDS Proxy
resource "aws_rds_proxy" "default" {
  name        = "my-rds-proxy"
  engine_family = "MYSQL"
  role_arns = [aws_iam_role.rds_role.arn]
  vpc_subnet_ids = [aws_subnet.rds_subnet_1.id, aws_subnet.rds_subnet_2.id]
  secrets = [aws_secretsmanager_secret.db_credentials.arn]
}

# 6. Aurora MySQL Cluster
resource "aws_rds_cluster" "default" {
  cluster_identifier      = "my-aurora-cluster"
  engine                  = "aurora-mysql"
  engine_mode             = "serverless"
  engine_version          = "5.7.mysql_aurora.2.11.2"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "YourStrongPassword"  # Replace with a secure password or use a secret
  db_subnet_group_name    = aws_db_subnet_group.default.name
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  skip_final_snapshot     = false
  final_snapshot_identifier = "snapshot"

  scaling_configuration {
    auto_pause               = true
    min_capacity             = 1
    max_capacity             = 2
    seconds_until_auto_pause = 300
  }
}

resource "aws_db_subnet_group" "default" {
  name       = "my-db-subnet-group"
  subnet_ids = [aws_subnet.rds_subnet_1.id, aws_subnet.rds_subnet_2.id]
}

# Associate proxy to the cluster
resource "aws_rds_proxy_target" "default" {
  target_group_name  = aws_rds_cluster.default.id
  proxy_name         = aws_rds_proxy.default.name
}
```

Key improvements and explanations:

*   **Clear Resource Definition:**  Each resource is defined with appropriate attributes and a clear purpose.
*   **IAM Role:** The IAM role provides RDS with permissions to retrieve credentials from Secrets Manager.
*   **Secrets Manager:**  Secrets Manager is used to securely store database credentials.
*   **RDS Proxy:**  An RDS Proxy is created for improved connection management.
*   **VPC and Subnets:** A VPC and subnets are defined for network isolation.
*   **Security Group:** A security group controls access to the RDS cluster, allowing traffic from the RDS Proxy.
*    **Final Snapshot:** Final snapshot functionality is implemented. The `skip_final_snapshot` is set to `false` and the `final_snapshot_identifier ` is set to "snapshot"
*   **Engine Mode:** The engine mode has been set to serverless for lower costs.
*   **Error Handling:** Credentials should be stored as secrets using aws\_secretsmanager\_secret. Replace YourStrongPassword with a secure password or a secret reference.
*   **Dependencies:** Correct dependencies are built into the Terraform graph to ensure proper resource creation order.

**Before running:**

1.  Replace placeholders like `"us-east-1"` and  `"YourStrongPassword"` with your actual values.  **Do not hardcode sensitive data like passwords directly in your Terraform code.** Use environment variables or a secret management tool.
2.  Ensure you have the AWS CLI configured with appropriate credentials and region.
3.  Review the security group rules carefully to ensure they meet your security requirements.
4.  Adjust the instance size and engine version as needed for your workload.

This configuration provides a robust and secure foundation for your Aurora MySQL cluster with RDS Proxy. Remember to adapt it to your specific needs and best practices for your environment.

