1.  **S3 Bucket:** We'll need an S3 bucket to hold the Glacier vault.
2.  **Glacier Vault:**  We'll create the Glacier vault within the S3 bucket.
3.  **Notification Configuration:** This is the core part. We'll configure the Glacier vault to send notifications to an SNS topic when archive retrieval is completed.
4.  **SNS Topic:** We'll also need to create an SNS topic to receive the notifications.
5.  **IAM Role:** A role will be created with the permission to publish to the SNS topic.

Here's the Terraform code:

```hcl
resource "aws_sns_topic" "glacier_retrieval_topic" {
  name = "glacier-retrieval-notifications"
}

resource "aws_iam_role" "glacier_notification_role" {
  name = "glacier_notification_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "glacier.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ],
  })
}

resource "aws_iam_policy" "glacier_notification_policy" {
  name = "glacier_notification_policy"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sns:Publish",
        Effect = "Allow",
        Resource = aws_sns_topic.glacier_retrieval_topic.arn
      },
    ],
  })
}

resource "aws_iam_role_policy_attachment" "glacier_notification_attachment" {
  role       = aws_iam_role.glacier_notification_role.name
  policy_arn = aws_iam_policy.glacier_notification_policy.arn
}


resource "aws_s3_bucket" "glacier_bucket" {
  bucket = "glacier-vault-bucket-unique"  # Replace with a unique bucket name
  acl    = "private"

  tags = {
    Name        = "Glacier Vault Bucket"
    Environment = "Dev"
  }
}

resource "aws_glacier_vault" "glacier_vault" {
  name = "glacier-vault-example"
  access_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Sid       = "AllowGlacierService"
        Effect    = "Allow"
        Principal = {
