Okay, let's break this down.  We need to create:

1.  **VPC:** A Virtual Private Cloud to house our resources.
2.  **Subnets:** At least two subnets (ideally in different Availability Zones) for high availability.
3.  **Security Group:**  A security group to allow traffic to the EC2 instance and NLB.
4.  **EC2 Instance:** A `t2.micro` instance in one of the subnets.
5.  **Network Load Balancer (NLB):**  An NLB configured to route traffic to the EC2 instance.  We'll need a target group for the NLB to point to.
6.  **Target Group:**  A target group associated with the NLB, registering our EC2 instance as a target.
7.  **Listener:** A listener on the NLB to accept traffic (e.g., on port 80).

Here's the Terraform configuration to accomplish that:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "nlb-vpc"
  }
}

# Subnets
resource "aws_subnet" "public_subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-a"
  }
}

resource "aws_subnet" "public_subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired AZ
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-b"
  }
}

# Security Group
resource "aws_security_group" "nlb_sg" {
  name        = "nlb-security-group"
  description = "Allow inbound traffic to EC2 instance and NLB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# EC2 Instance
resource "aws_instance" "example" {
  ami           = "ami-0c55b6919b8c9f42f" # Replace with a valid AMI for your region
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.public_subnet_a.id
  vpc_security_group_ids = [aws_security_group.nlb_sg.id]
  tags = {
    Name = "example-instance"
  }
}

# Target Group
resource "aws_lb_target_group" "example" {
  name     = "example-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
  health_check {
    path = "/"
    port = "traffic_port"
    interval = 30
    protocol = "HTTP"
    timeout = 5
    healthy_threshold = 2
    unhealthy_threshold = 2
  }
}

# Network Load Balancer
resource "aws_lb" "example" {
  name               = "example-nlb"
  internal           = false
  load_balancer_type = "network"
  subnets            = [aws_subnet.public_subnet_a.id, aws_subnet.public_subnet_b.id]
  enable_deletion_protection = false

  tags = {
    Name = "example-nlb"
  }
}

# Listener
resource "aws_lb_listener" "example" {
  load_balancer_arn = aws_lb.example.arn
  port              = 80
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.example.arn
  }
}

#Target Group Attachment
resource "aws_lb_target_group_attachment" "example" {
  target_group_arn = aws_lb_target_group.example.arn
  target_id        = aws_instance.example.id
  port             = 80
}
```

