  subnets            = [aws_subnet.glb_subnet_1.id, aws_subnet.glb_subnet_2.id]
  tags = {
    Name = "glb"
  }
}

# Listener
resource "aws_lb_listener" "glb_listener" {
  load_balancer_arn = aws_lb.glb.arn
  port              = "80"
  protocol          = "TCP"
  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.glb_target_group.arn
  }
}
