}

resource "aws_lb_listener" "my_listener" {
  load_balancer_arn = aws_lb.test.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

resource "aws_lb_target_group" "target_group" {
  target_type = "lambda"
}

resource "aws_lb_target_group_attachment" "ec2_attach" {
  target_group_arn = aws_lb_target_group.target_group.arn
  target_id = aws_lambda_function.example.arn
}

response:
Okay, let's break down the Terraform configuration needed for a Load Balancer with a Lambda function as the target. Here's the plan:

1.  **Lambda Function:** We'll need a basic Lambda function.  For simplicity, it won't do anything substantial, just acknowledge it's being invoked.
2.  **IAM Role for Lambda:** The Lambda function needs permissions to execute and write logs to CloudWatch.  We'll create an IAM role for this.
3.  **Application Load Balancer (ALB):** Create an ALB.
4.  **Target Group:** Create a Target Group that's specifically for Lambda functions.
5.  **ALB Listener:** Define a listener for the ALB (e.g., on port 80) that forwards traffic to the Lambda target group.
6.  **ALB Target Group Attachment:** Attach the Lambda function to the target group.

Here's the Terraform code to achieve this.  I'll include comments to explain each section.  I'm using AWS as the provider.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# 1. IAM Role for Lambda
resource "aws_iam_role" "lambda_role" {
  name               = "lambda-execution-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
        Effect = "Allow"
        Sid    = ""
      },
    ]
  })
}

resource "aws_iam_policy" "lambda_policy" {
  name        = "lambda-cloudwatch-policy"
  description = "Policy for Lambda to write to CloudWatch Logs"
  policy      = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_role_attachment" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_policy.arn
}

# 2. Lambda Function
resource "aws_lambda_function" "example" {
  function_name = "example-lambda"
  role          = aws_iam_role.lambda_role.arn
  handler       = "lambda_function.lambda_handler" # Replace if you have a different handler
  runtime       = "python3.9" # Or your preferred runtime.

  source_code_hash = filebase64("lambda_function.zip") # Replace with your lambda zipped code

  timeout = 30
}

# 3. Application Load Balancer
resource "aws_lb" "example" {
  name               = "example-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [] # Add your security groups here
  subnets            = []  # Add your subnet IDs here.
}

# 4. Target Group for Lambda
resource "aws_lb_target_group" "example" {
  name     = "example-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = "" # Replace with your VPC ID

  lambda_function_arn = aws_lambda_function.example.arn
}

# 5. ALB Listener
resource "aws_lb_listener" "example" {
  load_balancer_arn = aws_lb.example.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.example.arn
  }
}
```

