response:
 Okay, let's break down the Terraform configuration needed to create an Application Load Balancer (ALB) with a target group. Here's the plan:

1.  **VPC and Subnets:**  An ALB needs to live within a VPC and utilize at least two subnets. I'll define a basic VPC and a couple of public subnets for this example.  In a real deployment, you'd likely reference existing VPC and subnet infrastructure or have more sophisticated subnet configurations.
2.  **Security Groups:**  An ALB requires security groups to control inbound and outbound traffic. I’ll create one for the ALB itself allowing HTTP/HTTPS traffic from anywhere and another for the instances in the target group, allowing traffic from the ALB.
3.  **Target Group:** A target group determines how traffic is routed to your backend instances (EC2 instances in this case). We will create a target group to associate with our ALB.
4.  **Launch Template/Configuration:** To define the instances to be part of the target group, we'll use a launch template (or launch configuration - I'll use template for current best practice).
5.  **ALB:**  Finally, we'll create the ALB itself, associating it with the security groups and target group and specifying the listener(s).

Here’s the Terraform configuration:

```hcl
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "alb-vpc"
  }
}

resource "aws_subnet" "public_subnet_a" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "alb-subnet-a"
  }
}

resource "aws_subnet" "public_subnet_b" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  map_public_ip_on_launch = true
  tags = {
    Name = "alb-subnet-b"
  }
}

resource "aws_security_group" "alb_sg" {
  name        = "alb-sg"
  description = "Security group for the ALB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "instance_sg" {
  name        = "instance-sg"
  description = "Security group for instances"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_launch_template" "instance_template" {
  name_prefix   = "instance-template-"
  image_id      = "ami-0c55b6242982c2ff4" #replace with your desired AMI
  instance_type = "t2.micro"

  network_interfaces {
    security_groups = [aws_security_group.instance_sg.id]
  }
}

resource "aws_lb" "main" {
  name               = "alb-example"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public_subnet_a.id, aws_subnet.public_subnet_b.id]
}

resource "aws_lb_target_group" "main" {
  name     = "alb-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  health_check {
    path     = "/"
    protocol = "HTTP"
    interval = 30
    timeout  = 5
    healthy_threshold = 2
    unhealthy_threshold = 2
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.main.arn
  }
}

resource "aws_lb_target_group_attachment" "main" {
  target_group_arn = aws_lb_target_group.main.arn
  target_id        = aws_launch_template.instance_template.id # Attach using launch template ID
  port             = 80
}
```

