:Okay, let's outline the steps to fulfill this request.

1.  **RDS Instance (Primary):** We'll start by creating the primary RDS instance. This involves specifying details like engine (MySQL in this example, it can be changed), instance class, allocated storage, database name, username, and password.  We will manage the password securely using a random password generator.  We'll also need to set up the VPC security groups to allow access.

2.  **RDS Replica:** After the primary instance is created, we'll create a read replica. The replica will automatically synchronize data from the primary instance.

3.  **Security Group:** Create a security group to allow access to the RDS instances.

4.  **Outputs:** Output the primary instance endpoint and the replica endpoint for easy access.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!@#$%^&*"
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow inbound traffic to RDS instances"

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Replace with your desired CIDR blocks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_instance" "primary" {
  allocated_storage    = 20
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  name                 = "mydbprimary"
  password             = random_password.db_password.result
  username             = "admin"
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name = "default"  # Or your custom subnet group

  tags = {
    Name = "PrimaryRDS"
  }
}

resource "aws_db_instance" "replica" {
  identifier        = "mydbreplica"
  replicate_source_db = aws_db_instance.primary.id
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  username             = "admin"
  password             = random_password.db_password.result
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name = "default" # Or your custom subnet group

  tags = {
    Name = "ReplicaRDS"
  }
}

output "primary_endpoint" {
  value = aws_db_instance.primary.endpoint
}

output "replica_endpoint" {
  value = aws_db_instance.replica.endpoint
}
```

