1.  **Provider:** We need to configure the AWS provider.
2.  **VPC:** We'll define an `aws_vpc` resource with the CIDR block `10.0.0.0/16`.
3.  **Network ACL:** We'll define an `aws_network_acl` resource associated with the VPC.
4.  **Ingress Rules:**  We will add ingress rules to the network ACL to allow specific TCP traffic.
5.  **Egress Rules:** We will add egress rules to the network ACL to allow specific TCP traffic.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired AWS region
}

resource "aws_vpc" "main" {
  cidr_block       = "10.0.0.0/16"
  instance_tenancy = "default"

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_network_acl" "main" {
  vpc_id     = aws_vpc.main.id
  subnet_ids = [] # Subnets aren't defined in request

  tags = {
    Name = "main-acl"
  }
}

resource "aws_network_acl_rule" "ingress_http" {
  network_acl_id = aws_network_acl.main.id
  rule_number    = 100
  egress         = false
  protocol       = "tcp"
  port_range     = "80"
  cidr_block     = "0.0.0.0/0"
}

resource "aws_network_acl_rule" "ingress_https" {
  network_acl_id = aws_network_acl.main.id
  rule_number    = 110
  egress         = false
  protocol       = "tcp"
  port_range     = "443"
  cidr_block     = "0.0.0.0/0"
}

resource "aws_network_acl_rule" "egress_http" {
  network_acl_id = aws_network_acl.main.id
  rule_number    = 200
  egress         = true
  protocol       = "tcp"
  port_range     = "80"
  cidr_block     = "0.0.0.0/0"
}

resource "aws_network_acl_rule" "egress_https" {
  network_acl_id = aws_network_acl.main.id
  rule_number    = 210
  egress         = true
  protocol       = "tcp"
  port_range     = "443"
  cidr_block     = "0.0.0.0/0"
